1	/**
2	 * POST /api/cashier/payout — Process a ticket redemption or hand-pay payout.
3	 *
4	 * Called when a cashier redeems a TITO ticket or processes a machine hand-pay.
5	 * Validates that the cashier has sufficient float balance, creates a payout record
6	 * and a corresponding vault transaction, and decrements the shift's running balance.
7	 * Requires the vault shift to be reconciled before any payout can proceed.
8	 *
9	 * Body fields:
10	 * @param {string} cashierShiftId - Required. The ID of the cashier's active shift.
11	 * @param {string} type - Required. Payout type: 'ticket' or 'hand_pay'.
12	 * @param {number} amount - Required. Payout amount; must be > 0 and ≤ current float balance.
13	 * @param {string} [ticketNumber] - Conditional. Required when type is 'ticket'.
14	 * @param {string} [printedAt] - Optional. ISO timestamp when the ticket was printed; stored for audit.
15	 * @param {string} [machineId] - Conditional. Required when type is 'hand_pay'; used to look up
16	 *   machine serial number.
17	 * @param {string} [reason] - Optional. Description of the hand-pay reason; stored for audit.
18	 * @param {string} [notes] - Optional. Free-text notes attached to the payout record.
19	 *
20	 * ---
21	 *
22	 * GET /api/cashier/payout — Retrieve payout history.
23	 *
24	 * Returns payout records for the requesting cashier, or for any cashier if the
25	 * caller has VM-level access. Populates machineSerialNumber on hand-pay records
26	 * that pre-date the serial field for backward compatibility.
27	 *
28	 * Query parameters:
29	 * @param {string} [cashierShiftId] - Optional. Filter payouts to a specific shift.
30	 * @param {string} [cashierId] - Optional. VM only — filter by a specific cashier's user ID.
31	 * @param {number} [limit] - Optional. Maximum records to return. Defaults to 20.
32	 * @param {string} [startDate] - Optional. ISO date string lower bound on payout timestamp.
33	 * @param {string} [endDate] - Optional. ISO date string upper bound on payout timestamp.
34	 *
35	 * @module app/api/cashier/payout/route
36	 */
37	
38	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
39	import { connectDB } from '@/app/api/lib/middleware/db';
40	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
41	import { Machine } from '@/app/api/lib/models/machines';
42	import PayoutModel from '@/app/api/lib/models/payout';
43	import VaultShiftModel from '@/app/api/lib/models/vaultShift';
44	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
45	import {
46	  logRouteFetch,
47	  logRouteCreate,
48	  logRouteError,
49	  extractUserFromRequest,
50	} from '@/app/api/lib/utils/routeLogger';
51	import { generateMongoId } from '@/lib/utils/id';
52	import type { GamingMachine, PayoutDocument } from '@shared/types';
53	import type { CreatePayoutRequest } from '@/shared/types/vault';
54	import { NextRequest, NextResponse } from 'next/server';
55	
56	export async function POST(request: NextRequest) {
57	  const startTime = Date.now();
58	  const functionName = 'POST /api/cashier/payout';
59	  const user = extractUserFromRequest(request);
60	
61	  try {
62	    // ============================================================================
63	    // STEP 1: Authorization
64	    // ============================================================================
65	    const userPayload = await getUserFromServer();
66	    if (!userPayload) {
67	      logRouteError(
68	        functionName,
69	        'POST',
70	        '/api/cashier/payout',
71	        'Unauthorized',
72	        user
73	      );
74	      return NextResponse.json(
75	        { success: false, error: 'Unauthorized' },
76	        { status: 401 }
77	      );
78	    }
79	    const userId = userPayload._id as string;
80	
81	    // ============================================================================
82	    // STEP 2: Parse Request
83	    // ============================================================================
84	    const body: CreatePayoutRequest = await request.json();
85	    const {
86	      cashierShiftId,
87	      type,
88	      amount,
89	      ticketNumber,
90	      printedAt,
91	      machineId,
92	      reason,
93	      notes,
94	    } = body;
95	
96	    // Validate
97	    if (!cashierShiftId || !amount || amount <= 0) {
98	      logRouteError(
99	        functionName,
100	        'POST',
101	        '/api/cashier/payout',
102	        'Invalid payout data',
103	        user
104	      );
105	      return NextResponse.json(
106	        { success: false, error: 'Invalid payout data' },
107	        { status: 400 }
108	      );
109	    }
110	
111	    if (type === 'ticket' && !ticketNumber) {
112	      logRouteError(
113	        functionName,
114	        'POST',
115	        '/api/cashier/payout',
116	        'Ticket number required',
117	        user
118	      );
119	      return NextResponse.json(
120	        { success: false, error: 'Ticket number required' },
121	        { status: 400 }
122	      );
123	    }
124	
125	    if (type === 'hand_pay' && !machineId) {
126	      logRouteError(
127	        functionName,
128	        'POST',
129	        '/api/cashier/payout',
130	        'Machine identification required for Hand Pay',
131	        user
132	      );
133	      return NextResponse.json(
134	        {
135	          success: false,
136	          error: 'Machine identification required for Hand Pay',
137	        },
138	        { status: 400 }
139	      );
140	    }
141	
142	    // ============================================================================
143	    // STEP 3: DB Connection & Shift Check
144	    // ============================================================================
145	    await connectDB();
146	    const shift = await CashierShiftModel.findOne({
147	      _id: cashierShiftId,
148	      cashierId: userId,
149	      status: 'active',
150	    });
151	
152	    if (!shift) {
153	      logRouteError(
154	        functionName,
155	        'POST',
156	        '/api/cashier/payout',
157	        `Active cashier shift not found: ${cashierShiftId}`,
158	        user
159	      );
160	      return NextResponse.json(
161	        { success: false, error: 'Active cashier shift not found' },
162	        { status: 404 }
163	      );
164	    }
165	
166	    // ============================================================================
167	    // STEP 4: Check if Vault is reconciled
168	    // ============================================================================
169	    const vaultShift = await VaultShiftModel.findOne({
170	      _id: shift.vaultShiftId,
171	      status: 'active',
172	    });
173	
174	    if (!vaultShift?.isReconciled) {
175	      logRouteError(
176	        functionName,
177	        'POST',
178	        '/api/cashier/payout',
179	        'Vault is not reconciled',
180	        user
181	      );
182	      return NextResponse.json(
183	        {
184	          success: false,
185	          error:
186	            'Vault is not reconciled. Operation blocked until Vault Manager performs reconciliation.',
187	        },
188	        { status: 403 }
189	      );
190	    }
191	
192	    // Check Balance using live tracking
193	    const currentBalance = shift.currentBalance || 0;
194	
195	    if (currentBalance < amount) {
196	      logRouteError(
197	        functionName,
198	        'POST',
199	        '/api/cashier/payout',
200	        'Insufficient funds for payout',
201	        user
202	      );
203	      return NextResponse.json(
204	        { success: false, error: 'Insufficient funds for payout' },
205	        { status: 400 }
206	      );
207	    }
208	
209	    // ============================================================================
210	    // STEP 5: Fetch Machine Serial if Hand Pay
211	    // ============================================================================
212	    let machineSerialNumber = '';
213	    if (type === 'hand_pay' && machineId) {
214	      const machine = await Machine.findOne(
215	        { _id: machineId },
216	        { origSerialNumber: 1, 'custom.name': 1 }
217	      ).lean<GamingMachine>();
218	      machineSerialNumber =
219	        machine?.custom?.name || machine?.origSerialNumber || machineId;
220	    }
221	
222	    // ============================================================================
223	    // STEP 6: Process Payout
224	    // ============================================================================
225	    const now = new Date();
226	    const payoutId = await generateMongoId();
227	    const transactionId = await generateMongoId();
228	
229	    const payoutData: Record<string, unknown> = {
230	      _id: payoutId,
231	      locationId: shift.locationId,
232	      cashierId: userId,
233	      cashierShiftId: shift._id,
234	      type,
235	      amount,
236	      validated: true, // Mock validation for Phase 1
237	      timestamp: now,
238	      cashierFloatBefore: currentBalance,
239	      cashierFloatAfter: currentBalance - amount,
240	      transactionId, // Satisfy requirement before creation
241	      notes,
242	      createdAt: now,
243	    };
244	
245	    if (type === 'ticket') {
246	      payoutData.ticketNumber = ticketNumber;
247	      if (printedAt) payoutData.printedAt = new Date(printedAt);
248	    } else if (type === 'hand_pay') {
249	      payoutData.machineId = machineId;
250	      payoutData.machineSerialNumber = machineSerialNumber;
251	      payoutData.reason = reason;
252	    }
253	
254	    const payout = await PayoutModel.create(payoutData);
255	
256	    await VaultTransactionModel.create({
257	      _id: transactionId,
258	      locationId: shift.locationId,
259	      timestamp: now,
260	      type: 'payout',
261	      from: { type: 'cashier', id: userId },
262	      to: { type: 'external' }, // Customer
263	      amount,
264	      denominations: [], // No denomination tracking for payouts
265	      payoutId,
266	      cashierShiftId: shift._id,
267	      performedBy: userId,
268	      notes:
269	        type === 'hand_pay'
270	          ? `Payout (Hand Pay - ${machineSerialNumber})`
271	          : `Payout (Ticket Redemption - ${ticketNumber})`,
272	      isVoid: false,
273	      createdAt: now,
274	    });
275	
276	    // ============================================================================
277	    // STEP 7: Update Shift
278	    // ============================================================================
279	    shift.currentBalance -= amount;
280	    shift.payoutsTotal += amount;
281	    shift.payoutsCount += 1;
282	    await shift.save();
283	
284	    const duration = Date.now() - startTime;
285	    logRouteCreate(
286	      functionName,
287	      'POST',
288	      '/api/cashier/payout',
289	      1,
290	      user,
291	      duration
292	    );
293	    return NextResponse.json(
294	      {
295	        success: true,
296	        payout: payout.toObject(),
297	        newBalance: shift.currentBalance,
298	      },
299	      { status: 201 }
300	    );
301	  } catch (e) {
302	    const errorMessage = e instanceof Error ? e.message : 'Unknown error';
303	    logRouteError(
304	      functionName,
305	      'POST',
306	      '/api/cashier/payout',
307	      errorMessage,
308	      user
309	    );
310	    return NextResponse.json(
311	      { success: false, error: 'Internal server error' },
312	      { status: 500 }
313	    );
314	  }
315	}
316	
317	export async function GET(request: NextRequest) {
318	  const startTime = Date.now();
319	  const functionName = 'GET /api/cashier/payout';
320	  const user = extractUserFromRequest(request);
321	
322	  try {
323	    // ============================================================================
324	    // STEP 1: Authorization
325	    // ============================================================================
326	    const userPayload = await getUserFromServer();
327	    if (!userPayload) {
328	      logRouteError(
329	        functionName,
330	        'GET',
331	        '/api/cashier/payout',
332	        'Unauthorized',
333	        user
334	      );
335	      return NextResponse.json(
336	        { success: false, error: 'Unauthorized' },
337	        { status: 401 }
338	      );
339	    }
340	    const userId = userPayload._id as string;
341	    const userRoles = (userPayload?.roles as string[]) || [];
342	    const isVM = userRoles.some(role =>
343	      ['developer', 'admin', 'manager', 'vault-manager'].includes(
344	        role.toLowerCase()
345	      )
346	    );
347	
348	    // ============================================================================
349	    // STEP 2: Parse query parameters
350	    // ============================================================================
351	    const { searchParams } = new URL(request.url);
352	    const cashierShiftId = searchParams.get('cashierShiftId');
353	    const limit = parseInt(searchParams.get('limit') || '20');
354	    const startDate = searchParams.get('startDate');
355	    const endDate = searchParams.get('endDate');
356	
357	    // ============================================================================
358	    // STEP 3: Build Query
359	    // ============================================================================
360	    await connectDB();
361	    const query: Record<string, unknown> = {};
362	
363	    // SECURITY: If not VM, can only see their own payouts
364	    if (!isVM) {
365	      query.cashierId = userId;
366	    } else {
367	      const queryCashierId = searchParams.get('cashierId');
368	      if (queryCashierId) query.cashierId = queryCashierId;
369	    }
370	
371	    if (cashierShiftId) query.cashierShiftId = cashierShiftId;
372	
373	    if (startDate || endDate) {
374	      const timestampQuery: Record<string, Date> = {};
375	      if (startDate) timestampQuery.$gte = new Date(startDate);
376	      if (endDate) timestampQuery.$lte = new Date(endDate);
377	      query.timestamp = timestampQuery;
378	    }
379	
380	    // ============================================================================
381	    // STEP 4: Fetch Payouts
382	    // ============================================================================
383	    const payouts = await PayoutModel.find(query)
384	      .sort({ timestamp: -1 })
385	      .limit(limit)
386	      .lean<PayoutDocument[]>();
387	
388	    // Backward compatibility: Populate machineSerialNumber if missing
389	    const handPayPayouts = payouts.filter(
390	      p => p.type === 'hand_pay' && !p.machineSerialNumber && p.machineId
391	    );
392	    if (handPayPayouts.length > 0) {
393	      const machineIds = [...new Set(handPayPayouts.map(p => p.machineId))];
394	      const machines = await Machine.find(
395	        { _id: { $in: machineIds } },
396	        { origSerialNumber: 1, 'custom.name': 1 }
397	      ).lean<GamingMachine[]>();
398	      const machineMap = machines.reduce(
399	        (acc, m) => {
400	          acc[String(m._id)] =
401	            m?.custom?.name || m?.origSerialNumber || String(m._id);
402	          return acc;
403	        },
404	        {} as Record<string, string>
405	      );
406	
407	      payouts.forEach(p => {
408	        if (p.type === 'hand_pay' && !p.machineSerialNumber && p.machineId) {
409	          p.machineSerialNumber = machineMap[p.machineId] || p.machineId;
410	        }
411	      });
412	    }
413	
414	    const duration = Date.now() - startTime;
415	    logRouteFetch(
416	      functionName,
417	      'GET',
418	      '/api/cashier/payout',
419	      payouts.length,
420	      user,
421	      duration
422	    );
423	    return NextResponse.json({
424	      success: true,
425	      payouts,
426	    });
427	  } catch (e) {
428	    const errorMessage = e instanceof Error ? e.message : 'Unknown error';
429	    logRouteError(
430	      functionName,
431	      'GET',
432	      '/api/cashier/payout',
433	      errorMessage,
434	      user
435	    );
436	    return NextResponse.json(
437	      { success: false, error: 'Internal server error' },
438	      { status: 500 }
439	    );
440	  }
441	}
