1	/**
2	 * POST /api/cashier/shift/cancel
3	 *
4	 * Cancels the calling cashier's own pending shift request. Called when a cashier
5	 * wants to withdraw a shift-open request that is still awaiting Vault Manager
6	 * approval ('pending_start'), or to retract a close submission that is awaiting
7	 * review ('pending_review'). No request body is needed — the shift is resolved
8	 * from the authenticated session. Dismisses any associated VM notifications.
9	 *
10	 * No body fields — action is resolved entirely from the authenticated user's session.
11	 *
12	 * @module app/api/cashier/shift/cancel/route
13	 */
14	
15	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
16	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
19	import FloatRequestModel from '@/app/api/lib/models/floatRequest';
20	import {
21	  logRouteCreate,
22	  logRouteError,
23	  extractUserFromRequest,
24	} from '@/app/api/lib/utils/routeLogger';
25	import { markNotificationAsCancelledByEntity } from '@/lib/helpers/vault/notifications';
26	import { NextRequest, NextResponse } from 'next/server';
27	
28	export async function POST(request: NextRequest) {
29	  const startTime = Date.now();
30	  const functionName = 'POST /api/cashier/shift/cancel';
31	  const user = extractUserFromRequest(request);
32	  try {
33	    // ============================================================================
34	    // STEP 1: Authentication
35	    // ============================================================================
36	    const userPayload = await getUserFromServer();
37	    if (!userPayload) {
38	      logRouteError(
39	        functionName,
40	        'POST',
41	        '/api/cashier/shift/cancel',
42	        'Unauthorized',
43	        user
44	      );
45	      return NextResponse.json(
46	        { success: false, error: 'Unauthorized' },
47	        { status: 401 }
48	      );
49	    }
50	
51	    const userId = userPayload._id as string;
52	    const username = userPayload.username as string;
53	
54	    // ============================================================================
55	    // STEP 2: Connect to DB
56	    // ============================================================================
57	    await connectDB();
58	
59	    // ============================================================================
60	    // STEP 3: Find the pending or review shift for this cashier
61	    // ============================================================================
62	    const pendingShift = await CashierShiftModel.findOne({
63	      cashierId: userId,
64	      status: { $in: ['pending_start', 'pending_review'] },
65	    });
66	
67	    if (!pendingShift) {
68	      logRouteError(
69	        functionName,
70	        'POST',
71	        '/api/cashier/shift/cancel',
72	        'No cancellable shift request found',
73	        user
74	      );
75	      return NextResponse.json(
76	        { success: false, error: 'No cancellable shift request found' },
77	        { status: 404 }
78	      );
79	    }
80	
81	    const shiftId = pendingShift._id;
82	    const locationId = pendingShift.locationId;
83	    const currentStatus = pendingShift.status;
84	
85	    // ============================================================================
86	    // STEP 4: Handle based on status
87	    // ============================================================================
88	    if (currentStatus === 'pending_start') {
89	      // Find and handle associated float request
90	      const floatRequest = await FloatRequestModel.findOne({
91	        cashierShiftId: shiftId,
92	        status: 'pending',
93	      });
94	
95	      if (floatRequest) {
96	        // Mark notification as actioned (cancelled)
97	        try {
98	          await markNotificationAsCancelledByEntity(
99	            floatRequest._id,
100	            'float_request'
101	          );
102	        } catch (notifError) {
103	          console.error(
104	            'Failed to update notification status during cancel:',
105	            notifError
106	          );
107	        }
108	
109	        const floatUpdateResult = await FloatRequestModel.updateOne(
110	          { _id: floatRequest._id },
111	          {
112	            status: 'cancelled',
113	            updatedAt: new Date(),
114	            vmNotes: 'Request cancelled by cashier',
115	            $push: {
116	              auditLog: {
117	                action: 'cancelled',
118	                performedBy: userId,
119	                timestamp: new Date(),
120	                notes: 'Cancelled by cashier',
121	              },
122	            },
123	          }
124	        );
125	        if (floatUpdateResult.modifiedCount === 0) {
126	          return NextResponse.json(
127	            { success: false, error: 'Failed to cancel float request' },
128	            { status: 500 }
129	          );
130	        }
131	      }
132	
133	      // Update the pending shift to cancelled
134	      const cancelResult = await CashierShiftModel.updateOne(
135	        { _id: shiftId },
136	        {
137	          status: 'cancelled',
138	          closedAt: new Date(),
139	          notes: 'Shift opening request cancelled by cashier',
140	        }
141	      );
142	      if (cancelResult.modifiedCount === 0) {
143	        return NextResponse.json(
144	          { success: false, error: 'Failed to cancel shift' },
145	          { status: 500 }
146	        );
147	      }
148	
149	      // Audit Activity
150	      await logActivity({
151	        userId,
152	        username,
153	        action: 'cancel',
154	        details: `Cashier shift opening request cancelled by cashier`,
155	        metadata: {
156	          resource: 'cashier_shift',
157	          resourceId: shiftId,
158	          locationId,
159	          type: 'open_request',
160	        },
161	      });
162	    } else if (currentStatus === 'pending_review') {
163	      // Revert to Active
164	      const revertResult = await CashierShiftModel.updateOne(
165	        { _id: shiftId },
166	        {
167	          status: 'active',
168	          cashierEnteredBalance: undefined,
169	          cashierEnteredDenominations: [],
170	          closedAt: undefined,
171	          updatedAt: new Date(),
172	          $set: { notes: 'Close request cancelled by cashier' },
173	        }
174	      );
175	      if (revertResult.modifiedCount === 0) {
176	        return NextResponse.json(
177	          { success: false, error: 'Failed to revert shift to active' },
178	          { status: 500 }
179	        );
180	      }
181	
182	      // Mark Shift Review Notification as cancelled
183	      try {
184	        await markNotificationAsCancelledByEntity(shiftId, 'shift_review');
185	      } catch (notifError) {
186	        console.error(
187	          'Failed to update shift review notification during cancel:',
188	          notifError
189	        );
190	      }
191	
192	      // Audit Activity
193	      await logActivity({
194	        userId,
195	        username,
196	        action: 'cancel',
197	        details: `Cashier shift close request (pending review) cancelled by cashier. Reverted to active.`,
198	        metadata: {
199	          resource: 'cashier_shift',
200	          resourceId: shiftId,
201	          locationId,
202	          type: 'close_request',
203	        },
204	      });
205	    }
206	
207	    const duration = Date.now() - startTime;
208	    logRouteCreate(
209	      functionName,
210	      'POST',
211	      '/api/cashier/shift/cancel',
212	      1,
213	      user,
214	      duration
215	    );
216	    return NextResponse.json({
217	      success: true,
218	      message: 'Shift request cancelled successfully',
219	    });
220	  } catch (error) {
221	    const errorMessage =
222	      error instanceof Error ? error.message : 'Unknown error';
223	    logRouteError(
224	      functionName,
225	      'POST',
226	      '/api/cashier/shift/cancel',
227	      errorMessage,
228	      user
229	    );
230	    return NextResponse.json(
231	      { success: false, error: 'Internal server error' },
232	      { status: 500 }
233	    );
234	  }
235	}
