1	/**
2	 * POST /api/cashier/shift/close
3	 *
4	 * Submits a blind closing request for the cashier's active shift. Called when a
5	 * cashier physically counts their drawer and wants to end their session. The
6	 * cashier provides their physical count WITHOUT ever seeing the system's expected
7	 * balance (blind-close security feature C-4). The shift is always moved to
8	 * 'pending_review' and a Vault Manager notification is created regardless of
9	 * whether the count matches; the VM then resolves or rejects via /shift/resolve
10	 * or /shift/reject. Discrepancy amount is never returned to the cashier.
11	 *
12	 * Body fields:
13	 * @param shiftId      {string}   Required. The ID of the active cashier shift to close.
14	 * @param physicalCount {number}  Required. The total cash amount the cashier physically counted.
15	 * @param denominations {object[]} Required. Denomination breakdown of the physical count;
16	 *   individual values must sum exactly to physicalCount.
17	 *
18	 * @module app/api/cashier/shift/close/route
19	 */
20	
21	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
22	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
23	import { connectDB } from '@/app/api/lib/middleware/db';
24	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
25	import VaultShiftModel from '@/app/api/lib/models/vaultShift';
26	import {
27	  calculateExpectedBalance,
28	  validateDenominations,
29	} from '@/lib/helpers/vault/calculations';
