41	export async function POST(request: NextRequest) {
42	  const startTime = Date.now();
43	  const functionName = 'POST /api/cashier/shift/close';
44	  const user = extractUserFromRequest(request);
45	
46	  try {
47	    // ============================================================================
48	    // STEP 1: Authentication & Authorization
49	    // ============================================================================
50	    const userPayload = await getUserFromServer();
51	    if (!userPayload) {
52	      logRouteError(
53	        functionName,
54	        'POST',
55	        '/api/cashier/shift/close',
56	        'Unauthorized',
57	        user
58	      );
59	      return NextResponse.json(
60	        { success: false, error: 'Unauthorized' },
61	        { status: 401 }
62	      );
63	    }
64	    const userId = userPayload._id as string;
65	    const username = userPayload.username as string;
66	    const userRoles = (userPayload?.roles as string[]) || [];
67	
68	    const hasCashierAccess = userRoles.some((role: string) =>
69	      ['developer', 'admin', 'manager', 'cashier'].includes(role.toLowerCase())
70	    );
71	
72	    if (!hasCashierAccess) {
73	      logRouteError(
74	        functionName,
75	        'POST',
76	        '/api/cashier/shift/close',
77	        'Insufficient permissions',
78	        user
79	      );
80	      return NextResponse.json(
81	        { success: false, error: 'Insufficient permissions' },
82	        { status: 403 }
83	      );
84	    }
85	
86	    // ============================================================================
87	    // STEP 2: Parse and validate request
88	    // ============================================================================
89	    const body: CloseCashierShiftRequest = await request.json();
90	    const { shiftId, physicalCount, denominations } = body;
91	
92	    if (!shiftId || physicalCount === undefined || !denominations) {
93	      logRouteError(
94	        functionName,
95	        'POST',
96	        '/api/cashier/shift/close',
97	        'Missing required fields: shiftId, physicalCount, denominations',
98	        user
99	      );
100	      return NextResponse.json(
101	        {
102	          success: false,
103	          error:
104	            'Missing required fields: shiftId, physicalCount, denominations',
105	        },
106	        { status: 400 }
107	      );
108	    }
109	
110	    // ============================================================================
111	    // STEP 3: Validate denominations
112	    // ============================================================================
113	    const denominationValidation = validateDenominations(denominations);
114	    if (!denominationValidation.valid) {
115	      logRouteError(
116	        functionName,
117	        'POST',
118	        '/api/cashier/shift/close',
119	        'Invalid denominations',
120	        user
121	      );
122	      return NextResponse.json(
123	        {
124	          success: false,
125	          error: 'Invalid denominations',
126	          details: denominationValidation.errors,
127	        },
128	        { status: 400 }
129	      );
130	    }
131	
132	    if (denominationValidation.total !== physicalCount) {
133	      logRouteError(
134	        functionName,
135	        'POST',
136	        '/api/cashier/shift/close',
137	        `Denomination total ($${denominationValidation.total}) does not match physical count ($${physicalCount})`,
138	        user
139	      );
140	      return NextResponse.json(
141	        {
142	          success: false,
143	          error: `Denomination total ($${denominationValidation.total}) does not match physical count ($${physicalCount})`,
144	        },
145	        { status: 400 }
146	      );
147	    }
148	
149	    // ============================================================================
150	    // STEP 4: Connect to database
151	    // ============================================================================
152	    await connectDB();
153	
154	    // ============================================================================
155	    // STEP 5: Get cashier shift
156	    // ============================================================================
157	    const cashierShift = await CashierShiftModel.findOne({ _id: shiftId });
158	
159	    if (!cashierShift) {
160	      logRouteError(
161	        functionName,
162	        'POST',
163	        '/api/cashier/shift/close',
164	        'Cashier shift not found',
165	        user
166	      );
167	      return NextResponse.json(
168	        { success: false, error: 'Cashier shift not found' },
169	        { status: 404 }
170	      );
171	    }
172	
173	    // Verify this shift belongs to the logged-in cashier
174	    if (cashierShift.cashierId !== userId) {
175	      logRouteError(
176	        functionName,
177	        'POST',
178	        '/api/cashier/shift/close',
179	        'You can only close your own shift',
180	        user
181	      );
182	      return NextResponse.json(
183	        { success: false, error: 'You can only close your own shift' },
184	        { status: 403 }
185	      );
186	    }
187	
188	    if (cashierShift.status !== 'active') {
189	      logRouteError(
190	        functionName,
191	        'POST',
192	        '/api/cashier/shift/close',
193	        `Shift is already ${cashierShift.status}`,
194	        user
195	      );
196	      return NextResponse.json(
197	        {
198	          success: false,
199	          error: `Shift is already ${cashierShift.status}`,
200	        },
201	        { status: 400 }
202	      );
203	    }
204	
205	    // ============================================================================
206	    // STEP 6: Calculate expected balance
207	    // ============================================================================
208	    const expectedBalance = calculateExpectedBalance(
209	      cashierShift.openingBalance,
210	      cashierShift.payoutsTotal,
211	      cashierShift.floatAdjustmentsTotal
212	    );
213	
214	    // ============================================================================
215	    // STEP 7: Compare with cashier's physical count
216	    // ============================================================================
217	    const discrepancy = physicalCount - expectedBalance;
218	    const isMatch = Math.abs(discrepancy) < 0.01; // Allow for floating point precision
219	
220	    const now = new Date();
221	
222	    // ============================================================================
223	    // STEP 8: ALWAYS flag for review (C-4 CRITICAL)
224	    // ============================================================================
225	    cashierShift.cashierEnteredBalance = physicalCount;
226	    cashierShift.cashierEnteredDenominations = denominations;
227	    cashierShift.expectedClosingBalance = expectedBalance;
228	    cashierShift.closedAt = now;
229	    cashierShift.updatedAt = now;
230	    cashierShift.status = 'pending_review';
231	    cashierShift.discrepancy = discrepancy;
232	    cashierShift.discrepancyResolved = false;
233	    cashierShift.vmReviewNotes = undefined; // Clear any previous rejection notes
234	
235	    await cashierShift.save();
236	
237	    // Update vault shift canClose status (cannot close with pending review)
238	    await updateVaultCanClose(cashierShift.vaultShiftId);
239	
240	    // Create notification for VM (Phase 4)
241	    try {
242	      const { createShiftReviewNotification } =
243	        await import('@/lib/helpers/vault/notifications');
244	      const vaultShift = await VaultShiftModel.findOne({
245	        _id: cashierShift.vaultShiftId,
246	      });
247	      if (vaultShift?.vaultManagerId) {
248	        await createShiftReviewNotification(
249	          shiftId,
250	          cashierShift.locationId,
251	          username, // This is the cashier's username
252	          userId, // This is the cashier's user ID
253	          discrepancy,
254	          vaultShift.vaultManagerId
255	        );
256	      }
257	    } catch (notifError) {
258	      console.error('Failed to create shift review notification:', notifError);
259	    }
260	
261	    const response: CloseCashierShiftResponse = {
262	      success: true,
263	      status: 'pending_review',
264	      message: isMatch
265	        ? 'Shift submitted for review. Your count matches the system records. Please wait for manager confirmation.'
266	        : 'Shift submitted for review. There is a discrepancy in your count. Please wait for manager confirmation.',
267	    };
268	
269	    // Audit Activity
270	    await logActivity({
271	      userId,
272	      username,
273	      action: 'update',
274	      details: isMatch
275	        ? `Closed shift (Matched, await review). Closing Balance: $${physicalCount}`
276	        : `Closed shift with discrepancy. Physical: $${physicalCount}, Expected: $${expectedBalance}, Diff: $${discrepancy}`,
277	      metadata: {
278	        resource: 'cashier_shift',
279	        resourceId: shiftId,
280	        resourceName: 'Cashier Shift',
281	        vaultShiftId: cashierShift.vaultShiftId,
282	        status: 'pending_review',
283	        discrepancy,
284	        isMatch,
285	      },
286	    });
287	
288	    const duration = Date.now() - startTime;
289	    logRouteUpdate(
290	      functionName,
291	      'POST',
292	      '/api/cashier/shift/close',
293	      1,
294	      user,
295	      duration
296	    );
297	
298	    return NextResponse.json(response, { status: 200 });
299	  } catch (error) {
300	    const errorMessage =
301	      error instanceof Error ? error.message : 'Internal server error';
302	    logRouteError(
303	      functionName,
304	      'POST',
305	      '/api/cashier/shift/close',
306	      errorMessage,
307	      user
308	    );
309	    console.error('Error closing cashier shift:', error);
310	    return NextResponse.json(
311	      {
312	        success: false,
313	        error: 'Internal server error',
314	        details: error instanceof Error ? error.message : 'Unknown error',
315	      },
316	      { status: 500 }
317	    );
318	  }
319	}
