321	/**
322	 * Helper: Update vault shift canClose status based on cashier shifts
323	 */
324	async function updateVaultCanClose(vaultShiftId: string) {
325	  const cashierShifts = await CashierShiftModel.find({ vaultShiftId });
326	
327	  const hasActiveOrPending = cashierShifts.some(
328	    shift => shift.status === 'active' || shift.status === 'pending_review'
329	  );
330	
331	  const vaultUpdateResult = await VaultShiftModel.updateOne(
332	    { _id: vaultShiftId },
333	    { canClose: !hasActiveOrPending }
334	  );
335	  if (vaultUpdateResult.modifiedCount === 0) {
336	    console.warn(
337	      `[updateVaultCanClose] Vault shift ${vaultShiftId} not found or not modified`
338	    );
339	  }
340	}
