1	/**
2	 * GET /api/cashier/shift/current
3	 *
4	 * Returns the calling cashier's current open or pending shift. Called on every
5	 * cashier dashboard load to determine session state (no shift, pending approval,
6	 * active, or pending review). Also returns whether the location has an active
7	 * reconciled vault shift (needed to enable the shift-open button) and any
8	 * pending float requests associated with the current shift.
9	 *
10	 * No query parameters — shift is resolved entirely from the authenticated user's session.
11	 *
12	 * @module app/api/cashier/shift/current/route
13	 */
14	
15	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
