17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
19	import FloatRequestModel from '@/app/api/lib/models/floatRequest';
20	import VaultShiftModel from '@/app/api/lib/models/vaultShift';
21	import { calculateExpectedBalance } from '@/lib/helpers/vault/calculations';
22	import {
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	import { NextRequest, NextResponse } from 'next/server';
27	
28	export async function GET(request: NextRequest) {
29	  const functionName = 'GET /api/cashier/shift/current';
30	  const user = extractUserFromRequest(request);
31	
32	  try {
33	    // ============================================================================
34	    // STEP 1: Authorization
35	    // ============================================================================
36	    const userPayload = await getUserFromServer();
37	    if (!userPayload) {
38	      logRouteError(
39	        functionName,
40	        'GET',
41	        '/api/cashier/shift/current',
42	        'Unauthorized',
43	        user
44	      );
45	      return NextResponse.json(
46	        { success: false, error: 'Unauthorized' },
47	        { status: 401 }
48	      );
49	    }
50	    const userId = userPayload._id as string;
51	
52	    // ============================================================================
53	    // STEP 2: Find latest relevant shift
54	    // ============================================================================
55	    await connectDB();
56	
57	    // We look for any shift that is NOT closed, or closed very recently?
58	    // Mainly active, pending_start, pending_review.
59	    const shift = await CashierShiftModel.findOne({
60	      cashierId: userId,
61	      status: { $in: ['active', 'pending_start', 'pending_review'] },
62	    }).sort({ createdAt: -1 });
63	
64	    // ============================================================================
65	    // STEP 3: Check for active vault shift at user's location
66	    // ============================================================================
67	    const locationId = (userPayload.assignedLocations as string[])?.[0];
68	    let hasActiveVaultShift = false;
69	    let isVaultReconciled = false;
70	    if (locationId) {
71	      const activeVaultShift = await VaultShiftModel.findOne({
72	        locationId,
73	        status: 'active',
74	      });
75	      hasActiveVaultShift = !!activeVaultShift;
76	      isVaultReconciled = activeVaultShift?.isReconciled || false;
77	    }
78	
79	    if (!shift) {
80	      return NextResponse.json({
81	        success: true,
82	        shift: null,
83	        hasActiveVaultShift,
84	        isVaultReconciled,
85	      });
86	    }
87	
88	    // ============================================================================
89	    // STEP 4: Get current balance tracking
90	    // ============================================================================
91	    let currentBalance = 0;
92	    if (shift.status === 'active') {
93	      currentBalance =
94	        shift.currentBalance ||
95	        calculateExpectedBalance(
96	          shift.openingBalance,
97	          shift.payoutsTotal,
98	          shift.floatAdjustmentsTotal
99	        );
100	    }
101	
102	    // ============================================================================
103	    // STEP 5: Check for pending float movements (dual-approval flow)
104	    // ============================================================================
105	    // Only check for requests related to the current shift
106	    const pendingVmApproval = await FloatRequestModel.findOne({
107	      cashierId: userId,
108	      cashierShiftId: shift._id,
109	      status: 'approved_vm',
110	    }).sort({ updatedAt: -1 });
111	
112	    const pendingRequest = await FloatRequestModel.findOne({
113	      cashierId: userId,
114	      cashierShiftId: shift._id,
115	      status: 'pending',
116	    }).sort({ createdAt: -1 });
117	
118	    return NextResponse.json({
119	      success: true,
120	      shift: shift.toObject(),
121	      currentBalance, // Only relevant for active shifts
122	      status: shift.status,
123	      hasActiveVaultShift,
124	      isVaultReconciled,
125	      isStale: await isShiftStaleBackend(shift.openedAt, locationId),
126	      pendingVmApproval: pendingVmApproval
127	        ? pendingVmApproval.toObject()
128	        : null,
129	      pendingRequest: pendingRequest ? pendingRequest.toObject() : null,
130	    });
131	  } catch (error) {
132	    const errorMessage =
133	      error instanceof Error ? error.message : 'Internal server error';
134	    logRouteError(
135	      functionName,
136	      'GET',
137	      '/api/cashier/shift/current',
138	      errorMessage,
139	      user
140	    );
141	    console.error('Error fetching current shift:', error);
142	    return NextResponse.json(
143	      { success: false, error: 'Internal server error' },
144	      { status: 500 }
145	    );
146	  }
147	}
