44	        '/api/cashier/shift/reject',
45	        'Unauthorized',
46	        user
47	      );
48	      return NextResponse.json(
49	        { success: false, error: 'Unauthorized' },
50	        { status: 401 }
51	      );
52	    }
53	    const vaultManagerId = userPayload._id as string;
54	    const userRoles = (userPayload?.roles as string[]) || [];
55	    const hasVMAccess = userRoles.some(role =>
56	      ['developer', 'admin', 'manager', 'vault-manager'].includes(
57	        role.toLowerCase()
58	      )
59	    );
60	    if (!hasVMAccess) {
61	      logRouteError(
62	        functionName,
63	        'POST',
64	        '/api/cashier/shift/reject',
65	        'Insufficient permissions',
66	        user
67	      );
68	      return NextResponse.json(
69	        { success: false, error: 'Insufficient permissions' },
70	        { status: 403 }
71	      );
72	    }
73	
74	    // ============================================================================
75	    // STEP 2: Parse and validate request body
76	    // ============================================================================
77	    const body = await request.json();
78	    const { shiftId, reason = '' } = body;
79	
80	    if (!shiftId) {
81	      logRouteError(
82	        functionName,
83	        'POST',
84	        '/api/cashier/shift/reject',
85	        'Missing required field: shiftId',
86	        user
87	      );
