94	    // ============================================================================
95	    // STEP 3: Database connection
96	    // ============================================================================
97	    await connectDB();
98	
99	    // ============================================================================
100	    // STEP 4: Get cashier shift
101	    // ============================================================================
102	    const cashierShift = await CashierShiftModel.findOne({ _id: shiftId });
103	
104	    if (!cashierShift) {
105	      logRouteError(
106	        functionName,
107	        'POST',
108	        '/api/cashier/shift/reject',
109	        'Cashier shift not found',
110	        user
111	      );
112	      return NextResponse.json(
