1	/**
2	 * GET /api/cashier/shifts
3	 *
4	 * Returns a paginated, filtered list of cashier shifts. Called by the Vault
5	 * Manager dashboard to find shifts awaiting review and by the cashier history
6	 * view. Non-VM callers are silently restricted to their own shifts regardless
7	 * of the cashierId param. Results are joined with user and location collections
8	 * to include cashierName and locationName for display.
9	 *
10	 * Query parameters:
11	 * @param {string} [status] - Optional. Single status value or comma-separated list
12	 *   (e.g. 'pending_review' or 'active,pending_review') to filter by shift status.
13	 * @param {string} [locationId] - Optional. Restrict results to a specific location.
14	 * @param {string} [cashierId] - Optional. Filter by cashier user ID. Ignored for non-VM
15	 *   callers — they always see only their own shifts.
16	 * @param {number} [limit] - Optional. Maximum number of results to return. Defaults to 20.
17	 * @param {string} [startDate] - Optional. ISO date string; only return shifts created on or
18	 *   after this date.
19	 * @param {string} [endDate] - Optional. ISO date string; only return shifts created on or
20	 *   before this date.
21	 *
22	 * @module app/api/cashier/shifts/route
23	 */
24	
25	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
26	import { connectDB } from '@/app/api/lib/middleware/db';
27	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
28	import {
29	  logRouteFetch,
30	  logRouteError,
31	  extractUserFromRequest,
32	} from '@/app/api/lib/utils/routeLogger';
33	import { NextRequest, NextResponse } from 'next/server';
34	
35	export async function GET(request: NextRequest) {
36	  const startTime = Date.now();
37	  const functionName = 'GET /api/cashier/shifts';
38	  const user = extractUserFromRequest(request);
39	
40	  try {
41	    // ============================================================================
42	    // STEP 1: Authentication & Authorization
43	    // ============================================================================
44	    const userPayload = await getUserFromServer();
45	    if (!userPayload) {
46	      logRouteError(
47	        functionName,
48	        'GET',
49	        '/api/cashier/shifts',
50	        'Unauthorized',
51	        user
52	      );
53	      return NextResponse.json(
54	        { success: false, error: 'Unauthorized' },
55	        { status: 401 }
56	      );
57	    }
58	    const userRoles = (userPayload?.roles as string[]) || [];
59	    const userId = userPayload?._id as string;
60	    const isVM = userRoles.some(role =>
61	      ['developer', 'admin', 'manager', 'vault-manager'].includes(
62	        role.toLowerCase()
63	      )
64	    );
65	
66	    // ============================================================================
67	    // STEP 2: Parse query parameters
68	    // ============================================================================
69	    const { searchParams } = new URL(request.url);
70	    const status = searchParams.get('status');
71	    const locationId = searchParams.get('locationId');
72	    const cashierIdFromParams = searchParams.get('cashierId');
73	    const limit = parseInt(searchParams.get('limit') || '20');
74	    const startDate = searchParams.get('startDate');
75	    const endDate = searchParams.get('endDate');
76	
77	    // SECURITY: If not VM, you can ONLY see your own shifts
78	    let finalCashierId = cashierIdFromParams;
79	    if (!isVM) {
80	      finalCashierId = userId;
81	    }
82	
83	    const query: Record<string, unknown> = {};
84	    if (status) {
85	      if (status.includes(',')) {
86	        query.status = { $in: status.split(',') };
87	      } else {
88	        query.status = status;
89	      }
90	    }
91	    if (locationId) query.locationId = locationId;
92	    if (finalCashierId) query.cashierId = finalCashierId;
93	
94	    if (startDate || endDate) {
95	      const createdAtQuery: Record<string, Date> = {};
96	      if (startDate) createdAtQuery.$gte = new Date(startDate);
97	      if (endDate) createdAtQuery.$lte = new Date(endDate);
98	      query.createdAt = createdAtQuery;
99	    }
100	
101	    // ============================================================================
102	    // STEP 3: Database connection
103	    // ============================================================================
104	    await connectDB();
105	
106	    // ============================================================================
107	    // STEP 4: Fetch shifts
108	    // ============================================================================
109	    // Use aggregate to join with users collection to get cashier name if needed
110	    // But CashierShiftModel stores cashierId. We might need to fetch names separately or rely on frontend to know names if they are cached.
111	    // Ideally we should populate or store name.
112	    // For now, let's just fetch shifts. Frontend might need to look up names.
113	
114	    const shifts = await CashierShiftModel.aggregate([
115	      { $match: query },
116	      { $sort: { createdAt: -1 } },
117	      { $limit: limit },
118	      {
119	        $lookup: {
120	          from: 'users',
121	          localField: 'cashierId',
122	          foreignField: '_id',
123	          as: 'cashierInfo',
124	        },
125	      },
126	      {
127	        $addFields: {
128	          matchedUser: { $arrayElemAt: ['$cashierInfo', 0] },
129	        },
130	      },
131	      {
132	        $lookup: {
133	          from: 'gaminglocations', // Collection name for locations
134	          localField: 'locationId',
135	          foreignField: '_id',
136	          as: 'locationInfo',
137	        },
138	      },
139	      {
140	        $addFields: {
141	          matchedLocation: { $arrayElemAt: ['$locationInfo', 0] },
142	        },
143	      },
144	      {
145	        $addFields: {
146	          cashierUsername: '$matchedUser.username',
147	          locationName: '$matchedLocation.name',
148	          cashierName: {
149	            $let: {
150	              vars: {
151	                fullName: {
152	                  $trim: {
153	                    input: {
154	                      $concat: [
155	                        { $ifNull: ['$matchedUser.profile.firstName', ''] },
156	                        ' ',
157	                        { $ifNull: ['$matchedUser.profile.lastName', ''] },
158	                      ],
159	                    },
160	                  },
161	                },
162	              },
163	              in: {
164	                $cond: {
165	                  if: {
166	                    $and: [
167	                      { $ne: ['$$fullName', null] },
168	                      { $ne: ['$$fullName', ''] },
169	                      { $ne: ['$$fullName', ' '] },
170	                    ],
171	                  },
172	                  then: {
173	                    $concat: [
174	                      { $ifNull: ['$matchedUser.username', 'Cashier'] },
175	                      ' (',
176	                      '$$fullName',
177	                      ')',
178	                    ],
179	                  },
180	                  else: { $ifNull: ['$matchedUser.username', '$cashierId'] },
181	                },
182	              },
183	            },
184	          },
185	        },
186	      },
187	      {
188	        $project: {
189	          cashierInfo: 0,
190	          matchedUser: 0,
191	          locationInfo: 0,
192	          matchedLocation: 0,
193	        },
194	      },
195	    ]);
196	
197	    // ============================================================================
198	    // STEP 5: Return response
199	    // ============================================================================
200	    const duration = Date.now() - startTime;
201	    logRouteFetch(
202	      functionName,
203	      'GET',
204	      '/api/cashier/shifts',
205	      shifts.length,
206	      user,
207	      duration
208	    );
209	
210	    return NextResponse.json({
211	      success: true,
212	      shifts,
213	    });
214	  } catch (error) {
215	    const errorMessage =
216	      error instanceof Error ? error.message : 'Internal server error';
217	    logRouteError(
218	      functionName,
219	      'GET',
220	      '/api/cashier/shifts',
221	      errorMessage,
222	      user
223	    );
224	    console.error(
225	      '[GET] Error:',
226	      error instanceof Error ? error.message : 'Unknown error'
227	    );
228	    return NextResponse.json(
229	      { success: false, error: 'Internal server error' },
230	      { status: 500 }
231	    );
232	  }
233	}
