9	'use client';
10	
11	import { Badge } from '@/components/shared/ui/badge';
12	import {
13	  Card,
14	  CardContent,
15	  CardHeader,
16	  CardTitle,
17	} from '@/components/shared/ui/card';
18	import { useCurrencyFormat } from '@/lib/hooks/useCurrencyFormat';
19	import { useCashierActivity } from '@/lib/hooks/vault/useCashierActivity';
20	import { cn } from '@/lib/utils';
21	import {
22	  ArrowDownLeft,
23	  ArrowUpRight,
24	  CheckCircle2,
25	  ChevronLeft,
26	  ChevronRight,
27	  Clock,
28	  History,
29	  Loader2,
30	  MessageSquare,
31	  Tickets,
32	  XCircle,
33	} from 'lucide-react';
34	
35	import { AnimatePresence, motion } from 'framer-motion';
36	import { useCallback, useEffect, useState } from 'react';
37	import { toast } from 'sonner';
38	
39	export default function CashierActivitySection() {
40	  // ============================================================================
41	  // State & Hooks
42	  // ============================================================================
43	  const { activities, loading, refreshing, refresh } = useCashierActivity();
44	  const { formatAmount } = useCurrencyFormat();
45	  const [currentSlide, setCurrentSlide] = useState(0);
46	
47	  // ============================================================================
48	  // Computed
49	  // ============================================================================
50	  const slides = [
51	    {
52	      title: 'Welcome to Your Cash Desk!',
53	      description:
54	        "You haven't had any shift or float activity yet. Once you start your first shift, your activity logs will appear here.",
55	      icon: <History className="h-8 w-8 text-button" />,
56	      color: 'from-indigo-50',
57	    },
58	    {
59	      title: 'Process Payouts & Tickets',
60	      description:
61	        'Quickly handle player ticket redemptions and hand pay requests. Use the actions menu to manage payouts efficiently.',
62	      icon: <Tickets className="h-8 w-8 text-emerald-500" />,
63	      color: 'from-emerald-50',
64	    },
65	    {
66	      title: 'Vault Communications',
67	      description:
68	        'Stay updated on float request approvals and important vault messages. All your interactions are tracked in real-time.',
69	      icon: <MessageSquare className="h-8 w-8 text-orange-500" />,
70	      color: 'from-orange-50',
71	    },
72	  ];
73	
74	  const nextSlide = () => setCurrentSlide(prev => (prev + 1) % slides.length);
75	  const prevSlide = () =>
76	    setCurrentSlide(prev => (prev - 1 + slides.length) % slides.length);
77	
78	  // ============================================================================
79	  // Effects
80	  // ============================================================================
81	
82	  // Initial refresh
83	  useEffect(() => {
84	    refresh(false);
85	  }, [refresh]);
86	
87	  // Poll for updates every 30 seconds only if at least 2 items
88	  useEffect(() => {
89	    if (activities.length < 2) return;
90	
91	    const interval = setInterval(() => {
92	      refresh(true);
93	    }, 30000); // 30 seconds polling
94	    return () => clearInterval(interval);
95	  }, [refresh, activities.length]);
96	
97	  // ============================================================================
98	  // Handlers
99	  // ============================================================================
100	  const handleCancel = useCallback(
101	    async (requestId: string) => {
102	      try {
103	        const res = await fetch('/api/vault/float-request/cancel', {
104	          method: 'POST',
105	          headers: { 'Content-Type': 'application/json' },
106	          body: JSON.stringify({ requestId }),
107	        });
108	        const data = await res.json();
109	
110	        if (data.success) {
111	          toast.success('Request cancelled successfully');
112	          refresh(true);
113	        } else {
114	          toast.error(data.error || 'Failed to cancel request');
115	        }
116	      } catch {
117	        toast.error('Network error - could not cancel request');
118	      }
119	    },
120	    [refresh]
121	  );
122	
123	  // ============================================================================
124	  // Render
125	  // ============================================================================
126	
127	  // Guard: show skeleton during initial load
128	  if (loading && activities.length === 0) {
129	    // ... skeleton code ...
130	    return (
131	      <Card>
132	        <CardHeader>
133	          <CardTitle className="flex items-center gap-2 text-sm font-medium">
134	            <History className="h-4 w-4" />
135	            Recent Activity
136	          </CardTitle>
137	        </CardHeader>
138	        <CardContent>
139	          <div className="space-y-4">
140	            {[1, 2, 3, 4, 5].map(i => (
141	              <div key={i} className="flex items-center gap-3">
142	                <div className="h-10 w-10 animate-pulse rounded-full bg-gray-100" />
143	                <div className="flex-1 space-y-2">
144	                  <div className="h-4 w-32 animate-pulse rounded bg-gray-100" />
145	                  <div className="h-3 w-24 animate-pulse rounded bg-gray-100" />
146	                </div>
147	              </div>
148	            ))}
149	          </div>
150	        </CardContent>
151	      </Card>
152	    );
153	  }
154	
155	  // If NO activities at all (and no date filter), show the welcome slider
156	  if (activities.length === 0 && !loading) {
157	    const slide = slides[currentSlide];
158	    return (
159	      <div className="mt-4 border-t border-gray-100 pt-4">
160	        <Card
161	          className={`shadow-premium relative rounded-xl border-none bg-gradient-to-br ${slide.color} items-center justify-center border-t-4 border-t-button p-8 text-center transition-all duration-500`}
162	        >
163	          {/* Navigation Arrows */}
164	          <button
165	            onClick={prevSlide}
166	            className="absolute left-4 top-1/2 z-10 -translate-y-1/2 rounded-full bg-white/50 p-2 text-gray-400 shadow-sm transition-all hover:bg-white hover:text-button"
167	          >
168	            <ChevronLeft className="h-5 w-5" />
169	          </button>
170	          <button
171	            onClick={nextSlide}
172	            className="absolute right-4 top-1/2 z-10 -translate-y-1/2 rounded-full bg-white/50 p-2 text-gray-400 shadow-sm transition-all hover:bg-white hover:text-button"
173	          >
174	            <ChevronRight className="h-5 w-5" />
175	          </button>
176	
177	          <div className="duration-500 animate-in fade-in zoom-in-95">
178	            <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-white shadow-lg">
179	              {slide.icon}
180	            </div>
181	            <h3 className="mb-2 text-xl font-black text-gray-900">
182	              {slide.title}
183	            </h3>
184	            <p className="mx-auto min-h-[40px] max-w-sm text-sm text-gray-600">
185	              {slide.description}
186	            </p>
187	          </div>
188	
189	          <div className="mt-8 flex justify-center gap-3">
190	            {slides.map((_, idx) => (
191	              <button
192	                key={idx}
193	                onClick={() => setCurrentSlide(idx)}
194	                className={`rounded-full transition-all duration-300 ${
195	                  currentSlide === idx
196	                    ? 'h-2 w-6 bg-button'
197	                    : 'h-2 w-2 bg-button/20 hover:bg-button/40'
198	                }`}
199	              />
200	            ))}
201	          </div>
202	        </Card>
203	      </div>
204	    );
205	  }
206	
207	  const getStatusBadge = (status: string) => {
208	    switch (status) {
209	      case 'active':
210	      case 'approved':
211	      case 'completed':
212	        return (
213	          <Badge className="border-none bg-green-100 uppercase text-green-700 hover:bg-green-100">
214	            {status === 'active' ? 'APPROVED' : status}
215	          </Badge>
216	        );
217	      case 'pending':
218	      case 'pending_start':
219	        return (
220	          <Badge className="border-none bg-orange-100 text-orange-700 hover:bg-orange-100">
221	            PENDING
222	          </Badge>
223	        );
224	      case 'denied':
225	      case 'cancelled':
226	      case 'closed':
227	        return (
228	          <Badge className="border-none bg-red-100 uppercase text-red-700 hover:bg-red-100">
229	            {status}
230	          </Badge>
231	        );
232	      case 'pending_review':
233	        return (
234	          <Badge className="border-none bg-purple-100 uppercase text-purple-700 hover:bg-purple-100">
235	            REVIEW
236	          </Badge>
237	        );
238	      default:
239	        return <Badge variant="outline">{status}</Badge>;
240	    }
241	  };
242	
243	  const getIcon = (type: string, action: string, status: string) => {
244	    if (status === 'denied' || status === 'cancelled')
245	      return <XCircle className="h-5 w-5 text-red-400" />;
246	    if (status === 'pending' || status === 'pending_start')
247	      return <Clock className="h-5 w-5 text-orange-400" />;
248	
249	    if (action.includes('Increase'))
250	      return <ArrowUpRight className="h-5 w-5 text-blue-400" />;
251	    if (action.includes('Decrease'))
252	      return <ArrowDownLeft className="h-5 w-5 text-purple-400" />;
253	
254	    if (type === 'payout') return <Tickets className="h-5 w-5 text-red-400" />;
255	
256	    return <CheckCircle2 className="h-5 w-5 text-green-400" />;
257	  };
258	
259	  return (
260	    <div className="mt-4 border-t border-gray-100 pt-4">
261	      <Card className="rounded-lg border-t-4 border-orangeHighlight bg-container shadow-md duration-500 animate-in fade-in">
262	        <CardHeader className="flex flex-col items-start justify-between space-y-4 pb-4 sm:flex-row sm:items-center sm:space-y-0">
263	          <CardTitle className="flex items-center gap-2 text-base font-bold text-gray-900">
264	            <div className="flex h-8 w-8 items-center justify-center rounded border border-gray-300">
265	              <History className="h-4 w-4 text-orangeHighlight" />
266	            </div>
267	            Shift & Float History
268	          </CardTitle>
269	
270	          <div className="flex w-full items-center gap-3 sm:w-auto">
271	            <button
272	              onClick={() => refresh(true)}
273	              disabled={refreshing}
274	              className="flex items-center gap-1.5 whitespace-nowrap text-xs font-medium text-blue-600 hover:text-blue-700 disabled:opacity-50"
275	            >
276	              {refreshing && <Loader2 className="h-3 w-3 animate-spin" />}
277	              Refresh
278	            </button>
279	          </div>
280	        </CardHeader>
281	        <CardContent>
282	          <div className="space-y-1">
283	            {activities.length === 0 ? (
284	              <div className="rounded-lg border-2 border-dashed py-8 text-center text-sm italic text-gray-500">
285	                No recent activity found
286	              </div>
287	            ) : (
288	              <AnimatePresence initial={false}>
289	                {activities.map(activity => (
290	                  <motion.div
291	                    key={activity.id}
292	                    initial={{ opacity: 0, y: -10 }}
293	                    animate={{ opacity: 1, y: 0 }}
294	                    exit={{ opacity: 0, scale: 0.95 }}
295	                    transition={{ duration: 0.3 }}
296	                    className="flex items-start gap-4 rounded-lg border-b border-gray-100 p-3 transition-colors last:border-0 hover:bg-gray-50"
297	                  >
298	                    <div className="mt-1">
299	                      {getIcon(activity.type, activity.action, activity.status)}
300	                    </div>
301	                    <div className="min-w-0 flex-1">
302	                      <div className="flex items-center justify-between gap-2">
303	                        <p className="truncate text-sm font-bold text-gray-900">
304	                          {activity.action}
305	                        </p>
306	                        <div className="flex-shrink-0">
307	                          {activity.amount !== undefined && (
308	                            <span
309	                              className={cn(
310	                                'text-sm font-bold',
311	                                activity.isOutflow
312	                                  ? 'text-red-500'
313	                                  : 'text-button'
314	                              )}
315	                            >
316	                              {activity.isOutflow && '-'}
317	                              {formatAmount(activity.amount)}
318	                            </span>
319	                          )}
320	                        </div>
321	                      </div>
322	
323	                      <div className="mt-0.5 flex items-center gap-2">
324	                        <span className="font-mono text-[10px] uppercase tracking-wider text-gray-400">
325	                          {activity.timestamp.toLocaleDateString()}{' '}
326	                          {activity.timestamp.toLocaleTimeString([], {
327	                            hour: '2-digit',
328	                            minute: '2-digit',
329	                          })}
330	                        </span>
331	                        <span className="text-gray-300">•</span>
332	                        {getStatusBadge(activity.status)}
333	                      </div>
334	
335	                      {activity.notes && (
336	                        <p className="mt-2 line-clamp-2 rounded bg-gray-100/50 p-2 text-xs italic text-gray-600">
337	                          {activity.notes}
338	                        </p>
339	                      )}
340	
341	                      {activity.details && (
342	                        <p className="mt-1 text-[11px] font-bold text-red-600">
343	                          {activity.details}
344	                        </p>
345	                      )}
346	
347	                      {/* Cancel Action for Pending Requests */}
348	                      {activity.status === 'pending' && (
349	                        <div className="mt-2 flex justify-end">
350	                          <button
351	                            onClick={() => handleCancel(activity.id)}
352	                            className="rounded border border-transparent px-2 py-1 text-xs font-semibold text-red-500 transition-colors hover:border-red-100 hover:bg-red-50 hover:text-red-700"
353	                          >
354	                            Cancel Request
355	                          </button>
356	                        </div>
357	                      )}
358	                    </div>
359	                  </motion.div>
360	                ))}
361	              </AnimatePresence>
362	            )}
363	          </div>
364	        </CardContent>
365	      </Card>
366	    </div>
367	  );
368	}
