46	
47	type MappedPayout = {
48	  id: string;
49	  ticketNumber: string;
50	  amount: number;
51	  cashier: string;
52	  cashierId: string;
53	  station: string;
54	  processed: string;
55	  notes: string;
56	};
57	
58	export default function VaultPayoutsPageContent() {
59	  // ============================================================================
60	  // State & Hooks
61	  // ============================================================================
62	  const router = useRouter();
63	  const { user } = useUserStore();
64	  const { formatAmount } = useCurrencyFormat();
65	
66	  // Role detection
67	  const isAdminOrDev = user?.roles?.some(r =>
68	    ['admin', 'developer'].includes(r.toLowerCase())
69	  );
70	
71	  // -- State --
72	  const [loading, setLoading] = useState(true);
73	  const [payouts, setPayouts] = useState<MappedPayout[]>([]);
74	  const [sortOption, setSortOption] = useState<PayoutSortOption>('processed');
75	  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
76	  const [totalCount, setTotalCount] = useState(0);
77	
78	  const [showTicketForm, setShowTicketForm] = useState(false);
79	  const [showHandPayForm, setShowHandPayForm] = useState(false);
80	  const [machines, setMachines] = useState<GamingMachine[]>([]);
81	  const [actionLoading, setActionLoading] = useState(false);
82	
83	  const {
84	    shift,
85	    currentBalance,
86	    isVaultReconciled,
87	    isStaleShift,
88	    refresh: refreshShift,
89	  } = useCashierShift();
90	
91	  // ============================================================================
92	  // Handlers
93	  // ============================================================================
94	  // Note: fetchPayouts/fetchMachinesData declared before Effects since useEffect depends on them.
95	  const fetchPayouts = useCallback(async () => {
96	    setLoading(true);
97	    const locationId = user?.assignedLocations?.[0];
98	    if (!locationId) {
99	      setLoading(false);
100	      return;
101	    }
102	    try {
103	      const res = await fetch(
104	        `/api/vault/payouts?locationId=${locationId}&limit=50`
105	      );
106	      const data = await res.json();
107	      if (data.success) {
108	        setPayouts(
109	          data.payouts.map(
110	            (payoutItem: Record<string, unknown>): MappedPayout => ({
111	              id: String(payoutItem._id || ''),
112	              ticketNumber: String(
113	                payoutItem.ticketNumber ||
114	                  (payoutItem.type === 'hand_pay' ? 'Hand Pay' : 'N/A')
115	              ),
116	              amount: Number(payoutItem.amount || 0),
117	              cashier: String(
118	                payoutItem.cashierName || payoutItem.cashierId || 'Unknown'
119	              ),
120	              cashierId: String(payoutItem.cashierId || ''),
121	              station: 'Vault',
122	              processed: String(
123	                payoutItem.createdAt || payoutItem.timestamp || ''
124	              ),
125	              notes: String(payoutItem.notes || '-'),
126	            })
127	          )
128	        );
129	        setTotalCount(data.pagination.total);
130	      } else {
131	        toast.error('Failed to fetch payouts');
132	      }
133	    } catch (error) {
134	      toast.error('Connection error');
135	      console.error('Failed to fetch payouts', error);
136	    } finally {
137	      setLoading(false);
138	    }
139	  }, [user?.assignedLocations]);
140	
141	  const fetchMachinesData = useCallback(async () => {
142	    const locationId = user?.assignedLocations?.[0];
143	    if (!locationId) return;
144	    try {
145	      const res = await fetchCabinetsForLocation(
146	        locationId,
147	        undefined,
148	        'All Time'
149	      );
150	      if (res && res.data) {
151	        setMachines(res.data);
152	      }
153	    } catch (error) {
154	      console.error('Failed to fetch machines', error);
155	    }
156	  }, [user?.assignedLocations]);
157	
158	  // ============================================================================
159	  // Effects
160	  // ============================================================================
161	  useEffect(() => {
162	    fetchPayouts();
163	    fetchMachinesData();
164	  }, [fetchPayouts, fetchMachinesData]);
165	
166	  // Periodic refresh only if at least 2 items
167	  useEffect(() => {
168	    if (payouts.length < 2) return;
169	
170	    const interval = setInterval(() => {
171	      fetchPayouts();
172	    }, DEFAULT_POLL_INTERVAL);
173	
174	    return () => clearInterval(interval);
175	  }, [fetchPayouts, payouts.length]);
176	
177	  // ============================================================================
178	  // Computed
179	  // ============================================================================
180	
