67	  const [historySortOption, setHistorySortOption] =
68	    useState<FloatRequestSortOption>('processed');
69	  const [historySortOrder, setHistorySortOrder] = useState<'asc' | 'desc'>(
70	    'desc'
71	  );
72	
73	  // ============================================================================
74	  // Handlers
75	  // ============================================================================
76	  // Note: fetchRequests and mapRequests are declared before Effects since useEffect depends on them.
77	  const fetchRequests = async (isManual = false) => {
78	    const locationId = user?.assignedLocations?.[0];
79	
80	    // For Admins/Devs, we could handle global fetch here if API matures,
81	    // but at minimum ensure we don't spin forever
