86	    }
87	
88	    if (isManual) setRefreshing(true);
89	    else setLoading(true);
90	
91	    try {
92	      const [pendingRes, historyRes] = await Promise.all([
93	        fetch(
94	          `/api/vault/float-request?locationId=${locationId}&status=pending`
95	        ),
96	        fetch(
97	          `/api/vault/float-request?locationId=${locationId}&status=all&limit=${ITEMS_PER_PAGE}&page=${currentPage + 1}`
98	        ),
99	      ]);
100	
101	      if (pendingRes.ok) {
102	        const data = await pendingRes.json();
103	        if (data.success) {
104	          setPendingRequests(mapRequests(data.data || []));
105	        }
106	      }
107	
108	      if (historyRes.ok) {
109	        const data = await historyRes.json();
110	        if (data.success) {
111	          // Filter out pending from history to avoid duplication if API returns them in 'all'
112	          const historyRaw: Record<string, unknown>[] = data.data || [];
113	          const historyFiltered = historyRaw.filter(
114	            r => r.status !== 'pending'
115	          );
116	          setRequestHistory(mapRequests(historyFiltered));
117	
118	          // Handle pagination info from API if available, otherwise estimate
119	          if (data.pagination) {
120	            setTotalPages(data.pagination.totalPages || 1);
121	            setTotalItems(data.pagination.totalItems || historyFiltered.length);
122	          } else if (data.total) {
123	            // Alternate structure
124	            setTotalItems(data.total);
125	            setTotalPages(Math.ceil(data.total / ITEMS_PER_PAGE));
126	          }
127	        }
128	      }
129	    } catch (error) {
130	      console.error('Failed to fetch requests', error);
131	      toast.error('Failed to load float requests');
132	    } finally {
133	      setLoading(false);
134	      setRefreshing(false);
135	    }
136	  };
137	
138	  const mapRequests = (
139	    data: Record<string, unknown>[]
140	  ): MappedFloatRequest[] => {
141	    return data.map(r => ({
142	      id: String(r._id || ''),
143	      cashier: String(r.cashierName || r.cashierId || 'Unknown'),
144	      cashierId: String(r.cashierId || ''),
145	      station: 'Cash Desk',
146	      type:
147	        String(r.type || '').toLowerCase() === 'decrease'
148	          ? 'Decrease'
149	          : 'Increase',
150	      amount: Number(r.requestedAmount || 0),
151	      reason: String(r.requestNotes || ''),
152	      status:
153	        r.status === 'denied'
154	          ? 'rejected'
155	          : r.status === 'approved' || r.status === 'approved_vm'
156	            ? 'approved'
157	            : 'pending',
158	      requested: String(r.requestedAt || r.createdAt || ''),
159	      processed: String(r.processedAt || r.updatedAt || ''),
160	      processedBy: String(
161	        r.processedByName || r.processedBy || 'Vault Manager'
162	      ),
163	    }));
164	  };
165	
166	  // ============================================================================
167	  // Effects
168	  // ============================================================================
169	  useEffect(() => {
170	    fetchRequests();
171	  }, [user?.assignedLocations, currentPage]);
172	
173	  // Periodic refresh only if at least 2 items
174	  useEffect(() => {
175	    const totalItemsCount = pendingRequests.length + requestHistory.length;
176	    if (totalItemsCount < 2) return;
177	
178	    const interval = setInterval(() => {
179	      fetchRequests(true); // Silent refresh
180	    }, DEFAULT_POLL_INTERVAL);
181	
182	    return () => clearInterval(interval);
183	  }, [
184	    user?.assignedLocations,
185	    currentPage,
186	    pendingRequests.length,
187	    requestHistory.length,
188	  ]);
189	
190	  // ============================================================================
191	  // Computed
192	  // ============================================================================
193	
194	  // Actions
195	  const handleApprove = async (requestId: string) => {
196	    if (!isVaultReconciled) {
197	      toast.error('Reconciliation Required', {
198	        description:
199	          'Please perform the mandatory opening reconciliation before approving requests.',
200	      });
201	      return;
202	    }
203	    try {
204	      const res = await fetch(
205	        `/api/vault/float-requests/${requestId}/approve`,
206	        {
207	          method: 'POST', // or PUT
208	          headers: { 'Content-Type': 'application/json' },
209	          body: JSON.stringify({ approved: true }), // Body might be needed
210	        }
211	      );
212	      const data = await res.json();
213	      if (data.success) {
214	        toast.success(`Request approved`);
215	        fetchRequests();
216	      } else {
217	        toast.error(data.error || 'Failed to approve');
218	      }
219	    } catch (error) {
220	      toast.error('Connection error');
221	      console.error('Failed to approve request', error);
222	    }
223	  };
224	
225	  const handleReject = async (requestId: string) => {
226	    if (!isVaultReconciled) {
227	      toast.error('Reconciliation Required', {
228	        description:
229	          'Please perform the mandatory opening reconciliation before rejecting requests.',
230	      });
231	      return;
232	    }
233	    try {
234	      const res = await fetch(`/api/vault/float-requests/${requestId}/reject`, {
235	        method: 'POST',
236	        headers: { 'Content-Type': 'application/json' },
237	        body: JSON.stringify({ approved: false }), // Just in case
238	      });
239	      const data = await res.json();
240	      if (data.success) {
241	        toast.success(`Request rejected`);
242	        fetchRequests();
243	      } else {
244	        toast.error(data.error || 'Failed to reject');
245	      }
246	    } catch (error) {
247	      toast.error('Connection error');
248	      console.error('Failed to reject request', error);
249	    }
250	  };
251	
252	  // Sorting Logic (Client Side)
253	  const sortData = (
254	    data: MappedFloatRequest[],
255	    option: FloatRequestSortOption,
256	    order: 'asc' | 'desc'
257	  ) => {
258	    return [...data].sort((a, b) => {
259	      let aValue: string | number;
260	      let bValue: string | number;
261	
262	      switch (option) {
263	        case 'amount':
264	          aValue = Math.abs(a.amount);
265	          bValue = Math.abs(b.amount);
266	          break;
267	        case 'requested':
268	          aValue = new Date(a.requested).getTime();
269	          bValue = new Date(b.requested).getTime();
270	          break;
271	        case 'processed':
272	          aValue = new Date(a.processed).getTime();
273	          bValue = new Date(b.processed).getTime();
274	          break;
275	        case 'cashier':
276	          aValue = (a.cashier || '').toLowerCase();
277	          bValue = (b.cashier || '').toLowerCase();
278	          break;
279	        case 'type':
280	          aValue = (a.type || '').toLowerCase();
281	          bValue = (b.type || '').toLowerCase();
282	          break;
283	        case 'status':
284	          aValue = (a.status || '').toLowerCase();
285	          bValue = (b.status || '').toLowerCase();
286	          break;
287	        default:
288	          return 0;
289	      }
290	
291	      if (aValue < bValue) return order === 'asc' ? -1 : 1;
292	      if (aValue > bValue) return order === 'asc' ? 1 : -1;
293	      return 0;
294	    });
295	  };
296	
297	  const sortedPendingRequests = useMemo(
298	    () => sortData(pendingRequests, pendingSortOption, pendingSortOrder),
299	    [pendingRequests, pendingSortOption, pendingSortOrder]
300	  );
301	  const sortedRequestHistory = useMemo(
302	    () => sortData(requestHistory, historySortOption, historySortOrder),
303	    [requestHistory, historySortOption, historySortOrder]
304	  );
305	
306	  const handlePendingSort = (column: FloatRequestSortOption) => {
307	    if (pendingSortOption === column)
308	      setPendingSortOrder(pendingSortOrder === 'asc' ? 'desc' : 'asc');
309	    else {
310	      setPendingSortOption(column);
311	      setPendingSortOrder('asc');
312	    }
313	  };
314	
315	  const handleHistorySort = (column: FloatRequestSortOption) => {
316	    if (historySortOption === column)
317	      setHistorySortOrder(historySortOrder === 'asc' ? 'desc' : 'asc');
318	    else {
319	      setHistorySortOption(column);
320	      setHistorySortOrder('asc');
321	    }
322	  };
323	
324	  // ============================================================================
325	  // Render
326	  // ============================================================================
327	
328	  // Guard: show spinner during initial load
329	  if (loading && pendingRequests.length === 0 && requestHistory.length === 0) {
330	    return (
331	      <PageLayout>
332	        <div className="flex h-[50vh] items-center justify-center">
333	          <Loader2 className="h-8 w-8 animate-spin text-gray-400" />
334	        </div>
335	      </PageLayout>
336	    );
337	  }
338	
339	  return (
340	    <PageLayout onRefresh={() => fetchRequests(true)} refreshing={refreshing}>
341	      <div className="space-y-6">
342	        <VaultManagerHeader
343	          title="Float Requests"
344	          description="Review and process cashier float adjustment requests"
345	          backHref="/vault/management"
346	          onFloatActionComplete={() => fetchRequests(true)}
347	          showNotificationBell={false}
348	        >
349	          <Button
350	            onClick={() => fetchRequests(true)}
351	            disabled={refreshing}
352	            variant="ghost"
353	            size="sm"
354	            className="h-9 px-3 text-gray-400 hover:text-blue-600"
355	          >
356	            <RefreshCw
357	              className={`mr-2 h-4 w-4 ${refreshing ? 'animate-spin' : ''}`}
358	            />
359	            Refresh
360	          </Button>
361	        </VaultManagerHeader>
362	
363	        {/* Pending Requests Section */}
364	        {sortedPendingRequests.length > 0 && (
365	          <div className="space-y-4">
366	            <div className="flex items-center gap-2">
367	              <Clock className="h-5 w-5 text-orangeHighlight" />
368	              <h2 className="text-lg font-semibold text-gray-900">
369	                Pending Requests ({sortedPendingRequests.length})
370	              </h2>
371	            </div>
372	
373	            <VaultFloatRequestsTable
374	              requests={sortedPendingRequests}
375	              sortOption={pendingSortOption}
376	              sortOrder={pendingSortOrder}
377	              onSort={handlePendingSort}
378	              onApprove={handleApprove}
379	              onReject={handleReject}
380	              showActions={true}
381	              showHistory={false}
382	              disabled={!isVaultReconciled}
383	            />
384	          </div>
385	        )}
386	
387	        {/* Request History Section */}
388	        <div className="space-y-4">
389	          <div className="flex items-center gap-2">
390	            <CheckCircle2 className="h-5 w-5 text-button" />
391	            <h2 className="text-lg font-semibold text-gray-900">
392	              Request History
393	            </h2>
394	          </div>
395	
396	          <VaultFloatRequestsTable
397	            requests={sortedRequestHistory}
398	            sortOption={historySortOption}
399	            sortOrder={historySortOrder}
400	            onSort={handleHistorySort}
401	            showHistory={true}
402	          />
403	
404	          {totalPages > 0 && (
405	            <PaginationControls
406	              currentPage={currentPage}
407	              totalPages={totalPages}
408	              setCurrentPage={setCurrentPage}
409	              totalCount={totalItems}
410	              showTotalCount
411	            />
412	          )}
413	        </div>
414	      </div>
415	    </PageLayout>
416	  );
417	}
