/**
 * POST /api/cashier/payout — Process a ticket redemption or hand-pay payout.
 *
 * Called when a cashier redeems a TITO ticket or processes a machine hand-pay.
 * Validates that the cashier has sufficient float balance, creates a payout record
 * and a corresponding vault transaction, and decrements the shift's running balance.
 * Requires the vault shift to be reconciled before any payout can proceed.
 *
 * Body fields:
 * @param {string} cashierShiftId - Required. The ID of the cashier's active shift.
 * @param {string} type - Required. Payout type: 'ticket' or 'hand_pay'.
 * @param {number} amount - Required. Payout amount; must be > 0 and ≤ current float balance.
 * @param {string} [ticketNumber] - Conditional. Required when type is 'ticket'.
 * @param {string} [printedAt] - Optional. ISO timestamp when the ticket was printed; stored for audit.
 * @param {string} [machineId] - Conditional. Required when type is 'hand_pay'; used to look up
 *   machine serial number.
 * @param {string} [reason] - Optional. Description of the hand-pay reason; stored for audit.
 * @param {string} [notes] - Optional. Free-text notes attached to the payout record.
 *
 * ---
 *
 * GET /api/cashier/payout — Retrieve payout history.
 *
 * Returns payout records for the requesting cashier, or for any cashier if the
 * caller has VM-level access. Populates machineSerialNumber on hand-pay records
 * that pre-date the serial field for backward compatibility.
 *
 * Query parameters:
 * @param {string} [cashierShiftId] - Optional. Filter payouts to a specific shift.
 * @param {string} [cashierId] - Optional. VM only — filter by a specific cashier's user ID.
 * @param {number} [limit] - Optional. Maximum records to return. Defaults to 20.
 * @param {string} [startDate] - Optional. ISO date string lower bound on payout timestamp.
 * @param {string} [endDate] - Optional. ISO date string upper bound on payout timestamp.
 *
 * @module app/api/cashier/payout/route
 */

import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import { Machine } from '@/app/api/lib/models/machines';
import PayoutModel from '@/app/api/lib/models/payout';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
import {
  logRouteFetch,
  logRouteCreate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { generateMongoId } from '@/lib/utils/id';
import type { GamingMachine, PayoutDocument } from '@shared/types';
import type { CreatePayoutRequest } from '@/shared/types/vault';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/cashier/payout';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload }) => {
    try {
      const userId = userPayload._id as string;

      // ============================================================================
      // STEP 1: Parse Request
      // ============================================================================
      const body: CreatePayoutRequest = await request.json();
      const {
        cashierShiftId,
        type,
        amount,
        ticketNumber,
        printedAt,
        machineId,
        reason,
        notes,
      } = body;

      // Validate
      if (!cashierShiftId || !amount || amount <= 0) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/payout',
          'Invalid payout data',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Invalid payout data' },
          { status: 400 }
        );
      }

      if (type === 'ticket' && !ticketNumber) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/payout',
          'Ticket number required',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Ticket number required' },
          { status: 400 }
        );
      }

      if (type === 'hand_pay' && !machineId) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/payout',
          'Machine identification required for Hand Pay',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: 'Machine identification required for Hand Pay',
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 2: Shift Check
      // ============================================================================
      const shift = await CashierShiftModel.findOne({
        _id: cashierShiftId,
        cashierId: userId,
        status: 'active',
      });

      if (!shift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/payout',
          `Active cashier shift not found: ${cashierShiftId}`,
          user
        );
        return NextResponse.json(
          { success: false, error: 'Active cashier shift not found' },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 3: Check if Vault is reconciled
      // ============================================================================
      const vaultShift = await VaultShiftModel.findOne({
        _id: shift.vaultShiftId,
        status: 'active',
      });

      if (!vaultShift?.isReconciled) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/payout',
          'Vault is not reconciled',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error:
              'Vault is not reconciled. Operation blocked until Vault Manager performs reconciliation.',
          },
          { status: 403 }
        );
      }

      // Check Balance using live tracking
      const currentBalance = shift.currentBalance || 0;

      if (currentBalance < amount) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/payout',
          'Insufficient funds for payout',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Insufficient funds for payout' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 4: Fetch Machine Serial if Hand Pay
      // ============================================================================
      let machineSerialNumber = '';
      if (type === 'hand_pay' && machineId) {
        const machine = await Machine.findOne(
          { _id: machineId },
          { origSerialNumber: 1, 'custom.name': 1 }
        ).lean<GamingMachine>();
        machineSerialNumber =
          machine?.custom?.name || machine?.origSerialNumber || machineId;
      }

      // ============================================================================
      // STEP 5: Process Payout
      // ============================================================================
      const now = new Date();
      const payoutId = await generateMongoId();
      const transactionId = await generateMongoId();

      const payoutData: Record<string, unknown> = {
        _id: payoutId,
        locationId: shift.locationId,
        cashierId: userId,
        cashierShiftId: shift._id,
        type,
        amount,
        validated: true, // Mock validation for Phase 1
        timestamp: now,
        cashierFloatBefore: currentBalance,
        cashierFloatAfter: currentBalance - amount,
        transactionId, // Satisfy requirement before creation
        notes,
        createdAt: now,
      };

      if (type === 'ticket') {
        payoutData.ticketNumber = ticketNumber;
        if (printedAt) payoutData.printedAt = new Date(printedAt);
      } else if (type === 'hand_pay') {
        payoutData.machineId = machineId;
        payoutData.machineSerialNumber = machineSerialNumber;
        payoutData.reason = reason;
      }

      const payout = await PayoutModel.create(payoutData);

      await VaultTransactionModel.create({
        _id: transactionId,
        locationId: shift.locationId,
        timestamp: now,
        type: 'payout',
        from: { type: 'cashier', id: userId },
        to: { type: 'external' }, // Customer
        amount,
        denominations: [], // No denomination tracking for payouts
        payoutId,
        cashierShiftId: shift._id,
        performedBy: userId,
        notes:
          type === 'hand_pay'
            ? `Payout (Hand Pay - ${machineSerialNumber})`
            : `Payout (Ticket Redemption - ${ticketNumber})`,
        isVoid: false,
        createdAt: now,
      });

      // ============================================================================
      // STEP 6: Update Shift
      // ============================================================================
      shift.currentBalance -= amount;
      shift.payoutsTotal += amount;
      shift.payoutsCount += 1;
      await shift.save();

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
      logRouteCreate(
        functionName,
        'POST',
        '/api/cashier/payout',
        1,
        user,
        duration
      );
      return NextResponse.json(
        {
          success: true,
          payout: payout.toObject(),
          newBalance: shift.currentBalance,
        },
        { status: 201 }
      );
    } catch (e) {
      const errorMessage = e instanceof Error ? e.message : 'Unknown error';
      logRouteError(
        functionName,
        'POST',
        '/api/cashier/payout',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

export async function GET(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'GET /api/cashier/payout';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
    try {
      const userId = userPayload._id as string;
      const isVM = userRoles.some(role =>
        ['developer', 'admin', 'manager', 'vault-manager'].includes(
          role.toLowerCase()
        )
      );

      // ============================================================================
      // STEP 1: Parse query parameters
      // ============================================================================
      const { searchParams } = new URL(request.url);
      const cashierShiftId = searchParams.get('cashierShiftId');
      const limit = parseInt(searchParams.get('limit') || '20');
      const startDate = searchParams.get('startDate');
      const endDate = searchParams.get('endDate');

      // ============================================================================
      // STEP 2: Build Query
      // ============================================================================
      const query: Record<string, unknown> = {};

      // SECURITY: If not VM, can only see their own payouts
      if (!isVM) {
        query.cashierId = userId;
      } else {
        const queryCashierId = searchParams.get('cashierId');
        if (queryCashierId) query.cashierId = queryCashierId;
      }

      if (cashierShiftId) query.cashierShiftId = cashierShiftId;

      if (startDate || endDate) {
        const timestampQuery: Record<string, Date> = {};
        if (startDate) timestampQuery.$gte = new Date(startDate);
        if (endDate) timestampQuery.$lte = new Date(endDate);
        query.timestamp = timestampQuery;
      }

      // ============================================================================
      // STEP 3: Fetch Payouts
      // ============================================================================
      const payouts = await PayoutModel.find(query)
        .sort({ timestamp: -1 })
        .limit(limit)
        .lean<PayoutDocument[]>();

      // Backward compatibility: Populate machineSerialNumber if missing
      const handPayPayouts = payouts.filter(
        payoutItem =>
          payoutItem.type === 'hand_pay' &&
          !payoutItem.machineSerialNumber &&
          payoutItem.machineId
      );
      if (handPayPayouts.length > 0) {
        const machineIds = [
          ...new Set(handPayPayouts.map(payoutItem => payoutItem.machineId)),
        ];
        const machines = await Machine.find(
          { _id: { $in: machineIds } },
          { origSerialNumber: 1, 'custom.name': 1 }
        ).lean<GamingMachine[]>();
        const machineMap = machines.reduce(
          (acc, machine) => {
            acc[String(machine._id)] =
              machine?.custom?.name ||
              machine?.origSerialNumber ||
              String(machine._id);
            return acc;
          },
          {} as Record<string, string>
        );

        payouts.forEach(payoutItem => {
          if (
            payoutItem.type === 'hand_pay' &&
            !payoutItem.machineSerialNumber &&
            payoutItem.machineId
          ) {
            payoutItem.machineSerialNumber =
              machineMap[payoutItem.machineId] || payoutItem.machineId;
          }
        });
      }

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
      logRouteFetch(
        functionName,
        'GET',
        '/api/cashier/payout',
        payouts.length,
        user,
        duration
      );
      return NextResponse.json({
        success: true,
        payouts,
      });
    } catch (e) {
      const errorMessage = e instanceof Error ? e.message : 'Unknown error';
      logRouteError(
        functionName,
        'GET',
        '/api/cashier/payout',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

/**
 * POST /api/cashier/shift/cancel
 *
 * Cancels the calling cashier's own pending shift request. Called when a cashier
 * wants to withdraw a shift-open request that is still awaiting Vault Manager
 * approval ('pending_start'), or to retract a close submission that is awaiting
 * review ('pending_review'). No request body is needed — the shift is resolved
 * from the authenticated session. Dismisses any associated VM notifications.
 *
 * No body fields — action is resolved entirely from the authenticated user's session.
 *
 * @module app/api/cashier/shift/cancel/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import FloatRequestModel from '@/app/api/lib/models/floatRequest';
import {
  logRouteCreate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { markNotificationAsCancelledByEntity } from '@/lib/helpers/vault/notifications';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/cashier/shift/cancel';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload }) => {
    try {
      const userId = userPayload._id as string;
      const username = userPayload.username as string;

      // ============================================================================
      // STEP 1: Find the pending or review shift for this cashier
      // ============================================================================
      const pendingShift = await CashierShiftModel.findOne({
        cashierId: userId,
        status: { $in: ['pending_start', 'pending_review'] },
      });

      if (!pendingShift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/cancel',
          'No cancellable shift request found',
          user
        );
        return NextResponse.json(
          { success: false, error: 'No cancellable shift request found' },
          { status: 404 }
        );
      }

      const shiftId = pendingShift._id;
      const locationId = pendingShift.locationId;
      const currentStatus = pendingShift.status;

      // ============================================================================
      // STEP 2: Handle based on status
      // ============================================================================
      if (currentStatus === 'pending_start') {
        // Find and handle associated float request
        const floatRequest = await FloatRequestModel.findOne({
          cashierShiftId: shiftId,
          status: 'pending',
        });

        if (floatRequest) {
          // Mark notification as actioned (cancelled)
          try {
            await markNotificationAsCancelledByEntity(
              floatRequest._id,
              'float_request'
            );
          } catch (notifError) {
            console.error(
              'Failed to update notification status during cancel:',
              notifError
            );
          }

          const floatUpdateResult = await FloatRequestModel.updateOne(
            { _id: floatRequest._id },
            {
              status: 'cancelled',
              updatedAt: new Date(),
              vmNotes: 'Request cancelled by cashier',
              $push: {
                auditLog: {
                  action: 'cancelled',
                  performedBy: userId,
                  timestamp: new Date(),
                  notes: 'Cancelled by cashier',
                },
              },
            }
          );
          if (floatUpdateResult.modifiedCount === 0) {
            return NextResponse.json(
              { success: false, error: 'Failed to cancel float request' },
              { status: 500 }
            );
          }
        }

        // Update the pending shift to cancelled
        const cancelResult = await CashierShiftModel.updateOne(
          { _id: shiftId },
          {
            status: 'cancelled',
            closedAt: new Date(),
            notes: 'Shift opening request cancelled by cashier',
          }
        );
        if (cancelResult.modifiedCount === 0) {
          return NextResponse.json(
            { success: false, error: 'Failed to cancel shift' },
            { status: 500 }
          );
        }

        // Audit Activity
        await logActivity({
          userId,
          username,
          action: 'cancel',
          details: `Cashier shift opening request cancelled by cashier`,
          metadata: {
            resource: 'cashier_shift',
            resourceId: shiftId,
            locationId,
            type: 'open_request',
          },
        });
      } else if (currentStatus === 'pending_review') {
        // Revert to Active
        const revertResult = await CashierShiftModel.updateOne(
          { _id: shiftId },
          {
            status: 'active',
            cashierEnteredBalance: undefined,
            cashierEnteredDenominations: [],
            closedAt: undefined,
            updatedAt: new Date(),
            $set: { notes: 'Close request cancelled by cashier' },
          }
        );
        if (revertResult.modifiedCount === 0) {
          return NextResponse.json(
            { success: false, error: 'Failed to revert shift to active' },
            { status: 500 }
          );
        }

        // Mark Shift Review Notification as cancelled
        try {
          await markNotificationAsCancelledByEntity(shiftId, 'shift_review');
        } catch (notifError) {
          console.error(
            'Failed to update shift review notification during cancel:',
            notifError
          );
        }

        // Audit Activity
        await logActivity({
          userId,
          username,
          action: 'cancel',
          details: `Cashier shift close request (pending review) cancelled by cashier. Reverted to active.`,
          metadata: {
            resource: 'cashier_shift',
            resourceId: shiftId,
            locationId,
            type: 'close_request',
          },
        });
      }

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
      logRouteCreate(
        functionName,
        'POST',
        '/api/cashier/shift/cancel',
        1,
        user,
        duration
      );
      return NextResponse.json({
        success: true,
        message: 'Shift request cancelled successfully',
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Unknown error';
      logRouteError(
        functionName,
        'POST',
        '/api/cashier/shift/cancel',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

/**
 * POST /api/cashier/shift/close
 *
 * Submits a blind closing request for the cashier's active shift. Called when a
 * cashier physically counts their drawer and wants to end their session. The
 * cashier provides their physical count WITHOUT ever seeing the system's expected
 * balance (blind-close security feature C-4). The shift is always moved to
 * 'pending_review' and a Vault Manager notification is created regardless of
 * whether the count matches; the VM then resolves or rejects via /shift/resolve
 * or /shift/reject. Discrepancy amount is never returned to the cashier.
 *
 * Body fields:
 * @param shiftId      {string}   Required. The ID of the active cashier shift to close.
 * @param physicalCount {number}  Required. The total cash amount the cashier physically counted.
 * @param denominations {object[]} Required. Denomination breakdown of the physical count;
 *   individual values must sum exactly to physicalCount.
 *
 * @module app/api/cashier/shift/close/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import {
  calculateExpectedBalance,
  validateDenominations,
} from '@/lib/helpers/vault/calculations';
import type {
  CloseCashierShiftRequest,
  CloseCashierShiftResponse,
} from '@/shared/types/vault';
import {
  logRouteUpdate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/cashier/shift/close';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
    try {
      const userId = userPayload._id as string;
      const username = userPayload.username as string;

      // ============================================================================
      // STEP 1: Authorization check
      // ============================================================================
      const hasCashierAccess = userRoles.some((role: string) =>
        ['developer', 'admin', 'manager', 'cashier'].includes(role.toLowerCase())
      );

      if (!hasCashierAccess) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          'Insufficient permissions',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Insufficient permissions' },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 2: Parse and validate request
      // ============================================================================
      const body: CloseCashierShiftRequest = await request.json();
      const { shiftId, physicalCount, denominations } = body;

      if (!shiftId || physicalCount === undefined || !denominations) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          'Missing required fields: shiftId, physicalCount, denominations',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error:
              'Missing required fields: shiftId, physicalCount, denominations',
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Validate denominations
      // ============================================================================
      const denominationValidation = validateDenominations(denominations);
      if (!denominationValidation.valid) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          'Invalid denominations',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: 'Invalid denominations',
            details: denominationValidation.errors,
          },
          { status: 400 }
        );
      }

      if (denominationValidation.total !== physicalCount) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          `Denomination total ($${denominationValidation.total}) does not match physical count ($${physicalCount})`,
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: `Denomination total ($${denominationValidation.total}) does not match physical count ($${physicalCount})`,
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 4: Get cashier shift
      // ============================================================================
      const cashierShift = await CashierShiftModel.findOne({ _id: shiftId });

      if (!cashierShift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          'Cashier shift not found',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Cashier shift not found' },
          { status: 404 }
        );
      }

      // Verify this shift belongs to the logged-in cashier
      if (cashierShift.cashierId !== userId) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          'You can only close your own shift',
          user
        );
        return NextResponse.json(
          { success: false, error: 'You can only close your own shift' },
          { status: 403 }
        );
      }

      if (cashierShift.status !== 'active') {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/close',
          `Shift is already ${cashierShift.status}`,
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: `Shift is already ${cashierShift.status}`,
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 5: Calculate expected balance
      // ============================================================================
      const expectedBalance = calculateExpectedBalance(
        cashierShift.openingBalance,
        cashierShift.payoutsTotal,
        cashierShift.floatAdjustmentsTotal
      );

      // ============================================================================
      // STEP 6: Compare with cashier's physical count
      // ============================================================================
      const discrepancy = physicalCount - expectedBalance;
      const isMatch = Math.abs(discrepancy) < 0.01; // Allow for floating point precision

      const now = new Date();

      // ============================================================================
      // STEP 7: ALWAYS flag for review (C-4 CRITICAL)
      // ============================================================================
      cashierShift.cashierEnteredBalance = physicalCount;
      cashierShift.cashierEnteredDenominations = denominations;
      cashierShift.expectedClosingBalance = expectedBalance;
      cashierShift.closedAt = now;
      cashierShift.updatedAt = now;
      cashierShift.status = 'pending_review';
      cashierShift.discrepancy = discrepancy;
      cashierShift.discrepancyResolved = false;
      cashierShift.vmReviewNotes = undefined; // Clear any previous rejection notes

      await cashierShift.save();

      // Update vault shift canClose status (cannot close with pending review)
      await updateVaultCanClose(cashierShift.vaultShiftId);

      // Create notification for VM (Phase 4)
      try {
        const { createShiftReviewNotification } =
          await import('@/lib/helpers/vault/notifications');
        const vaultShift = await VaultShiftModel.findOne({
          _id: cashierShift.vaultShiftId,
        });
        if (vaultShift?.vaultManagerId) {
          await createShiftReviewNotification(
            shiftId,
            cashierShift.locationId,
            username, // This is the cashier's username
            userId, // This is the cashier's user ID
            discrepancy,
            vaultShift.vaultManagerId
          );
        }
      } catch (notifError) {
        console.error('Failed to create shift review notification:', notifError);
      }

      const response: CloseCashierShiftResponse = {
        success: true,
        status: 'pending_review',
        message: isMatch
          ? 'Shift submitted for review. Your count matches the system records. Please wait for manager confirmation.'
          : 'Shift submitted for review. There is a discrepancy in your count. Please wait for manager confirmation.',
      };

      // Audit Activity
      await logActivity({
        userId,
        username,
        action: 'update',
        details: isMatch
          ? `Closed shift (Matched, await review). Closing Balance: $${physicalCount}`
          : `Closed shift with discrepancy. Physical: $${physicalCount}, Expected: $${expectedBalance}, Diff: $${discrepancy}`,
        metadata: {
          resource: 'cashier_shift',
          resourceId: shiftId,
          resourceName: 'Cashier Shift',
          vaultShiftId: cashierShift.vaultShiftId,
          status: 'pending_review',
          discrepancy,
          isMatch,
        },
      });

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
      logRouteUpdate(
        functionName,
        'POST',
        '/api/cashier/shift/close',
        1,
        user,
        duration
      );

      return NextResponse.json(response, { status: 200 });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'POST',
        '/api/cashier/shift/close',
        errorMessage,
        user
      );
      return NextResponse.json(
        {
          success: false,
          error: 'Internal server error',
          details: error instanceof Error ? error.message : 'Unknown error',
        },
        { status: 500 }
      );
    }
  });
}

/**
 * Helper: Update vault shift canClose status based on cashier shifts
 */
async function updateVaultCanClose(vaultShiftId: string) {
  const cashierShifts = await CashierShiftModel.find({ vaultShiftId });

  const hasActiveOrPending = cashierShifts.some(
    shift => shift.status === 'active' || shift.status === 'pending_review'
  );

  const vaultUpdateResult = await VaultShiftModel.updateOne(
    { _id: vaultShiftId },
    { canClose: !hasActiveOrPending }
  );
  if (vaultUpdateResult.modifiedCount === 0) {
    console.warn(
      `[updateVaultCanClose] Vault shift ${vaultShiftId} not found or not modified`
    );
  }
}

/**
 * GET /api/cashier/shift/current
 *
 * Returns the calling cashier's current open or pending shift. Called on every
 * cashier dashboard load to determine session state (no shift, pending approval,
 * active, or pending review). Also returns whether the location has an active
 * reconciled vault shift (needed to enable the shift-open button) and any
 * pending float requests associated with the current shift.
 *
 * No query parameters — shift is resolved entirely from the authenticated user's session.
 *
 * @module app/api/cashier/shift/current/route
 */

import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { isShiftStaleBackend } from '@/app/api/lib/helpers/vault/gamingDay';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import FloatRequestModel from '@/app/api/lib/models/floatRequest';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import { calculateExpectedBalance } from '@/lib/helpers/vault/calculations';
import {
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

export async function GET(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'GET /api/cashier/shift/current';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload }) => {
    try {
      const userId = userPayload._id as string;

      // ============================================================================
      // STEP 1: Find latest relevant shift
      // ============================================================================
      const shift = await CashierShiftModel.findOne({
        cashierId: userId,
        status: { $in: ['active', 'pending_start', 'pending_review'] },
      }).sort({ createdAt: -1 });

      // ============================================================================
      // STEP 2: Check for active vault shift at user's location
      // ============================================================================
      const locationId = (userPayload.assignedLocations as string[])?.[0];
      let hasActiveVaultShift = false;
      let isVaultReconciled = false;
      if (locationId) {
        const activeVaultShift = await VaultShiftModel.findOne({
          locationId,
          status: 'active',
        });
        hasActiveVaultShift = !!activeVaultShift;
        isVaultReconciled = activeVaultShift?.isReconciled || false;
      }

      if (!shift) {
        return NextResponse.json({
          success: true,
          shift: null,
          hasActiveVaultShift,
          isVaultReconciled,
        });
      }

      // ============================================================================
      // STEP 3: Get current balance tracking
      // ============================================================================
      let currentBalance = 0;
      if (shift.status === 'active') {
        currentBalance =
          shift.currentBalance ||
          calculateExpectedBalance(
            shift.openingBalance,
            shift.payoutsTotal,
            shift.floatAdjustmentsTotal
          );
      }

      // ============================================================================
      // STEP 4: Check for pending float movements (dual-approval flow)
      // ============================================================================
      const pendingVmApproval = await FloatRequestModel.findOne({
        cashierId: userId,
        cashierShiftId: shift._id,
        status: 'approved_vm',
      }).sort({ updatedAt: -1 });

      const pendingRequest = await FloatRequestModel.findOne({
        cashierId: userId,
        cashierShiftId: shift._id,
        status: 'pending',
      }).sort({ createdAt: -1 });

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);

      return NextResponse.json({
        success: true,
        shift: shift.toObject(),
        currentBalance, // Only relevant for active shifts
        status: shift.status,
        hasActiveVaultShift,
        isVaultReconciled,
        isStale: await isShiftStaleBackend(shift.openedAt, locationId),
        pendingVmApproval: pendingVmApproval
          ? pendingVmApproval.toObject()
          : null,
        pendingRequest: pendingRequest ? pendingRequest.toObject() : null,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'GET',
        '/api/cashier/shift/current',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

/**
 * POST /api/cashier/shift/open
 *
 * Initiates a cashier shift opening request. Called when a cashier starts their
 * working session — creates a shift in 'pending_start' status and submits a float
 * request to the Vault Manager for approval before the shift goes active.
 * Requires an active, reconciled vault shift at the location and the cashier to
 * be assigned to that location. Fails if the cashier already has an open shift.
 *
 * Body fields:
 * @param locationId    {string}   Required. The location ID where the shift is being opened.
 * @param requestedFloat {number}  Required. The total float amount requested for this shift.
 * @param denominations {object[]} Required. Denomination breakdown of the float; individual
 *   values must sum exactly to requestedFloat.
 *
 * @module app/api/cashier/shift/open/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import FloatRequestModel from '@/app/api/lib/models/floatRequest';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import { validateDenominations } from '@/lib/helpers/vault/calculations';
import { generateMongoId } from '@/lib/utils/id';
import type { OpenCashierShiftRequest } from '@/shared/types/vault';
import {
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/cashier/shift/open';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
    try {
      const userId = userPayload._id as string;
      const username = userPayload.username as string;

      // ============================================================================
      // STEP 1: Authorization check
      // ============================================================================
      const hasCashierAccess = userRoles.some((role: string) =>
        ['developer', 'admin', 'manager', 'cashier'].includes(role.toLowerCase())
      );

      if (!hasCashierAccess) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          'Insufficient permissions',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Insufficient permissions' },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 2: Parse and validate request
      // ============================================================================
      const body: OpenCashierShiftRequest = await request.json();
      const { locationId, requestedFloat, denominations } = body;

      if (!locationId || requestedFloat === undefined || !denominations) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          'Missing required fields: locationId, requestedFloat, denominations',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error:
              'Missing required fields: locationId, requestedFloat, denominations',
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Validate denominations
      // ============================================================================
      const denominationValidation = validateDenominations(denominations);
      if (!denominationValidation.valid) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          'Invalid denominations',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: 'Invalid denominations',
            details: denominationValidation.errors,
          },
          { status: 400 }
        );
      }

      if (denominationValidation.total !== requestedFloat) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          `Denomination total ($${denominationValidation.total}) does not match requested float ($${requestedFloat})`,
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: `Denomination total ($${denominationValidation.total}) does not match requested float ($${requestedFloat})`,
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 4: Check for active Vault Shift
      // ============================================================================
      const vaultShift = await VaultShiftModel.findOne({
        locationId,
        status: 'active',
      });

      if (!vaultShift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          'No active vault shift found',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error:
              'No active vault shift found. Please ask a Vault Manager to open the vault.',
          },
          { status: 400 }
        );
      }

      if (!vaultShift.isReconciled) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          'Vault is not reconciled',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error:
              'Vault is not reconciled. Please ask a Vault Manager to perform the mandatory opening reconciliation.',
          },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 5: Ensure cashier is assigned to this location
      // ============================================================================
      const assignedLocations =
        (userPayload.assignedLocations as string[]) || [];
      if (!assignedLocations.includes(locationId)) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          'You are not assigned to this location',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: 'You are not assigned to this location.',
          },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 6: Check if cashier already has an active or pending shift
      // ============================================================================
      const existingShift = await CashierShiftModel.findOne({
        cashierId: userId,
        status: { $in: ['active', 'pending_start', 'pending_review'] },
      });

      if (existingShift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/open',
          `You already have a shift with status: ${existingShift.status}`,
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: `You already have a shift with status: ${existingShift.status}`,
          },
          { status: 409 }
        );
      }

      // ============================================================================
      // STEP 7: Create Cashier Shift (Pending Start)
      // ============================================================================
      const shiftId = await generateMongoId();
      const now = new Date();

      const cashierShift = await CashierShiftModel.create({
        _id: shiftId,
        locationId,
        cashierId: userId,
        vaultShiftId: vaultShift._id,
        status: 'pending_start',
        openedAt: now,
        openingBalance: requestedFloat,
        openingDenominations: denominations,
        payoutsTotal: 0,
        payoutsCount: 0,
        floatAdjustmentsTotal: 0,
        createdAt: now,
        updatedAt: now,
      });

      // ============================================================================
      // STEP 8: Create Float Request
      // ============================================================================
      const requestId = await generateMongoId();
      const floatRequest = await FloatRequestModel.create({
        _id: requestId,
        locationId,
        cashierId: userId,
        cashierShiftId: shiftId,
        vaultShiftId: vaultShift._id,
        type: 'increase', // Initial float is essentially an increase from 0
        requestedAmount: requestedFloat,
        requestedDenominations: denominations,
        requestNotes: 'Initial shift float',
        requestedAt: now,
        status: 'pending',
        createdAt: now,
        updatedAt: now,
      });

      // ============================================================================
      // STEP 9: Audit Activity
      // ============================================================================
      await logActivity({
        userId,
        username,
        action: 'create',
        details: `Cashier shift opened (pending approval) for location ${locationId} with float $${requestedFloat}`,
        metadata: {
          resource: 'cashier_shift',
          resourceId: shiftId,
          resourceName: 'Cashier Shift',
          locationId: locationId,
          floatRequestId: requestId,
        },
      });

      // ============================================================================
      // STEP 10: Create notification for Vault Manager
      // ============================================================================
      try {
        const { createFloatRequestNotification } =
          await import('@/lib/helpers/vault/notifications');
        // Target the VM who opened the vault shift
        if (vaultShift.vaultManagerId) {
          await createFloatRequestNotification(
            floatRequest.toObject(),
            username, // Using username as cashierName for now
            vaultShift.vaultManagerId
          );
        }
      } catch (notifError) {
        console.error(
          'Failed to create notification but shift request was created:',
          notifError
        );
        // We don't fail the whole request if only notification fails
      }

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);

      return NextResponse.json(
        {
          success: true,
          message: 'Shift request submitted. Waiting for Vault Manager approval.',
          shift: cashierShift.toObject(),
          floatRequest: floatRequest.toObject(),
        },
        { status: 201 }
      );
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'POST',
        '/api/cashier/shift/open',
        errorMessage,
        user
      );
      return NextResponse.json(
        {
          success: false,
          error: 'Internal server error',
          details: error instanceof Error ? error.message : 'Unknown error',
        },
        { status: 500 }
      );
    }
  });
}

/**
 * POST /api/cashier/shift/reject
 *
 * Allows a Vault Manager to reject a cashier shift that is awaiting review
 * ('pending_review'). Called when the VM determines the cashier's physical count
 * is unacceptable and the cashier should recount and resubmit. Reverts the shift
 * to 'active' status so the cashier can submit a new closing count. The VM's
 * rejection reason is stored on the shift but is not revealed to the cashier as
 * a discrepancy amount.
 *
 * Body fields:
 * @param shiftId {string} Required. The ID of the 'pending_review' cashier shift to reject.
 * @param reason  {string} Optional. The VM's explanation for the rejection; stored on the
 *   shift for audit purposes.
 *
 * @module app/api/cashier/shift/reject/route
 */
import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import {
  logRouteUpdate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/cashier/shift/reject';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
    try {
      const vaultManagerId = userPayload._id as string;

      // ============================================================================
      // STEP 1: Authorization check
      // ============================================================================
      const hasVMAccess = userRoles.some(role =>
        ['developer', 'admin', 'manager', 'vault-manager'].includes(
          role.toLowerCase()
        )
      );
      if (!hasVMAccess) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/reject',
          'Insufficient permissions',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Insufficient permissions' },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 2: Parse and validate request body
      // ============================================================================
      const body = await request.json();
      const { shiftId, reason = '' } = body;

      if (!shiftId) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/reject',
          'Missing required field: shiftId',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Missing required field: shiftId' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Get cashier shift
      // ============================================================================
      const cashierShift = await CashierShiftModel.findOne({ _id: shiftId });

      if (!cashierShift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/reject',
          'Cashier shift not found',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Cashier shift not found' },
          { status: 404 }
        );
      }

      if (cashierShift.status !== 'pending_review') {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/reject',
          `Shift is not pending review (status: ${cashierShift.status})`,
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: `Shift is not pending review (status: ${cashierShift.status})`,
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 4: Revert to Active
      // ============================================================================
      const now = new Date();

      cashierShift.status = 'active';
      cashierShift.vmReviewNotes = reason;
      cashierShift.reviewedBy = vaultManagerId;
      cashierShift.reviewedAt = now;
      cashierShift.updatedAt = now;

      // We keep the entered closing data so the cashier can see what they entered vs expected
      // It will be overwritten when they re-submit.

      await cashierShift.save();

      // ============================================================================
      // STEP 5: Audit Activity
      // ============================================================================
      await logActivity({
        userId: vaultManagerId as string,
        username: userPayload.username as string,
        action: 'update',
        details: `Rejected shift review. Reverted to active. Reason: ${reason}`,
        metadata: {
          resource: 'cashier_shift',
          resourceId: shiftId,
          resourceName: 'Cashier Shift',
          vaultShiftId: cashierShift.vaultShiftId,
          reason,
          status: 'active',
        },
      });

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
      logRouteUpdate(
        functionName,
        'POST',
        '/api/cashier/shift/reject',
        1,
        user,
        duration
      );

      // ============================================================================
      // STEP 6: Update Vault Shift canClose status
      // ============================================================================
      await updateVaultCanClose(cashierShift.vaultShiftId);

      return NextResponse.json({
        success: true,
        message: 'Shift closure request rejected. Shift is now active again.',
        shift: cashierShift,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'POST',
        '/api/cashier/shift/reject',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

/**
 * Helper: Update vault shift canClose status based on cashier shifts
 */
async function updateVaultCanClose(vaultShiftId: string) {
  const cashierShifts = await CashierShiftModel.find({ vaultShiftId });

  const hasActiveOrPending = cashierShifts.some(
    shift => shift.status === 'active' || shift.status === 'pending_review'
  );

  const vaultUpdateResult = await VaultShiftModel.updateOne(
    { _id: vaultShiftId },
    { canClose: !hasActiveOrPending }
  );
  if (vaultUpdateResult.modifiedCount === 0) {
    console.warn(
      `[updateVaultCanClose] Vault shift ${vaultShiftId} not found or not modified`
    );
  }
}

/**
 * POST /api/cashier/shift/resolve
 *
 * Allows a Vault Manager to finalize and close a cashier shift that is awaiting
 * review ('pending_review'). Called after the VM has verified the cashier's
 * physical count; the VM may override the closing balance (e.g. to correct a
 * discrepancy) and must supply an audit comment explaining any adjustment.
 * Closing the shift creates a 'cashier_shift_close' vault transaction returning
 * the confirmed float to the vault, and increments the vault shift's canClose
 * flag if no other shifts remain open.
 *
 * Body fields:
 * @param shiftId       {string}   Required. The ID of the 'pending_review' cashier shift to resolve.
 * @param finalBalance  {number}   Required. The VM-confirmed closing balance (may differ from
 *   cashier's physical count if an override is applied).
 * @param auditComment  {string}   Optional. Mandatory justification when the VM overrides the
 *   balance; stored permanently on the shift for compliance audits.
 * @param denominations {object[]} Optional. VM-adjusted denomination breakdown matching
 *   finalBalance; overwrites the cashier's submitted denominations if provided.
 *
 * @module app/api/cashier/shift/resolve/route
 */
import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import CashierShiftModel from '@/app/api/lib/models/cashierShift';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
import { generateMongoId } from '@/lib/utils/id';
import {
  logRouteUpdate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/cashier/shift/resolve';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
    try {
      const vaultManagerId = userPayload._id as string;

      // ============================================================================
      // STEP 1: Authorization check
      // ============================================================================
      const hasVMAccess = userRoles.some(role =>
        ['developer', 'admin', 'manager', 'vault-manager'].includes(
          role.toLowerCase()
        )
      );
      if (!hasVMAccess) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/resolve',
          'Insufficient permissions',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Insufficient permissions' },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 2: Parse and validate request body
      // ============================================================================
      const body = await request.json();
      const { shiftId, finalBalance, auditComment = '', denominations } = body;

      if (!shiftId || finalBalance === undefined) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/resolve',
          'Missing required fields (shiftId, finalBalance)',
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: 'Missing required fields (shiftId, finalBalance)',
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Get cashier shift
      // ============================================================================
      const cashierShift = await CashierShiftModel.findOne({ _id: shiftId });

      if (!cashierShift) {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/resolve',
          'Cashier shift not found',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Cashier shift not found' },
          { status: 404 }
        );
      }

      if (cashierShift.status !== 'pending_review') {
        logRouteError(
          functionName,
          'POST',
          '/api/cashier/shift/resolve',
          `Shift is not pending review (status: ${cashierShift.status})`,
          user
        );
        return NextResponse.json(
          {
            success: false,
            error: `Shift is not pending review (status: ${cashierShift.status})`,
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 4: Resolve and Close Shift
      // ============================================================================
      const now = new Date();

      cashierShift.status = 'closed';
      cashierShift.closingBalance = finalBalance;
      if (denominations && denominations.length > 0) {
        cashierShift.closingDenominations = denominations;
        cashierShift.vmAdjustedDenominations = denominations;
      }
      cashierShift.vmAdjustedBalance = finalBalance;
      cashierShift.vmReviewNotes = auditComment;
      cashierShift.reviewedBy = vaultManagerId;
      cashierShift.reviewedAt = now;
      cashierShift.discrepancyResolved = true;
      cashierShift.updatedAt = now;

      await cashierShift.save();

      // ============================================================================
      // STEP 5: Create Closing Transaction
      // ============================================================================
      // Return the final confirmed float amount to vault
      const transactionId = await generateMongoId();
      await VaultTransactionModel.create({
        _id: transactionId,
        locationId: cashierShift.locationId,
        timestamp: now,
        type: 'cashier_shift_close',
        from: { type: 'cashier', id: cashierShift.cashierId },
        to: { type: 'vault' },
        amount: finalBalance,
        denominations: denominations || [], // Use adjusted denominations if provided
        cashierBalanceBefore: finalBalance,
        cashierBalanceAfter: 0,
        vaultShiftId: cashierShift.vaultShiftId,
        cashierShiftId: shiftId,
        performedBy: vaultManagerId,
        notes: `Shift resolved by VM. Comment: ${auditComment}`,
        isVoid: false,
        createdAt: now,
      });

      // ============================================================================
      // STEP 6: Audit Activity
      // ============================================================================
      await logActivity({
        userId: vaultManagerId as string,
        username: userPayload.username as string,
        action: 'update',
        details: `Resolved shift discrepancy. Final Balance: $${finalBalance}. Comment: ${auditComment}`,
        metadata: {
          resource: 'cashier_shift',
          resourceId: shiftId,
          resourceName: 'Cashier Shift',
          transactionId,
          vaultShiftId: cashierShift.vaultShiftId,
          vmAdjustedBalance: finalBalance,
          comment: auditComment,
        },
      });

      const duration = Date.now() - startTime;
      if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
      logRouteUpdate(
        functionName,
        'POST',
        '/api/cashier/shift/resolve',
        1,
        user,
        duration
      );

      // ============================================================================
      // STEP 7: Update Vault Shift canClose status
      // ============================================================================
      await updateVaultCanClose(cashierShift.vaultShiftId);

      return NextResponse.json({
        success: true,
        message: 'Shift resolved and closed successfully',
        shift: cashierShift,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'POST',
        '/api/cashier/shift/resolve',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: 'Internal server error' },
        { status: 500 }
      );
    }
  });
}

/**
 * Helper: Update vault shift canClose status based on cashier shifts
 */
async function updateVaultCanClose(vaultShiftId: string) {
  const cashierShifts = await CashierShiftModel.find({ vaultShiftId });

  const hasActiveOrPending = cashierShifts.some(
